async function init() {
  initializeDateFilters_();
  await resolveApiUrlConfiguration_();
  renderApp();

  if (state.user) {
    if (isStudentSession_()) {
      void bootstrapStudentPortal_().catch(handleError);
    } else {
      bootstrapApplicationInBackground_({
        message: "Preparando Dashboard Iglesia..."
      });
    }
  }
}

async function resolveApiUrlConfiguration_() {
  const localOverrideActive = hasStoredApiUrlOverride();

  if (localOverrideActive) {
    state.apiUrl = getStoredApiUrl();
  }

  try {
    const config = await apiGet("app.config.get", {}, {
      apiUrl: APP_CONFIG.defaultApiUrl
    });
    const configuredGlobalUrl = normalizeApiUrlForComparison_(config?.apiUrl);
    const resolvedGlobalUrl = configuredGlobalUrl || APP_CONFIG.defaultApiUrl;

    state.globalApiUrl = resolvedGlobalUrl;
    setRuntimeApiUrl(resolvedGlobalUrl);

    if (!localOverrideActive) {
      state.apiUrl = resolvedGlobalUrl;
    }
  } catch (error) {
    state.globalApiUrl = APP_CONFIG.defaultApiUrl;
    setRuntimeApiUrl(APP_CONFIG.defaultApiUrl);

    if (!localOverrideActive) {
      state.apiUrl = APP_CONFIG.defaultApiUrl;
    }
  }
}

function isStudentSession_() {
  return state.user?.sessionType === "student";
}

function initializeDateFilters_() {
  const dashboardRange = getDefaultRecentRange_(90);
  const congregantsRange = getDefaultRecentRange_(30);

  if (!state.filters.dashboard.recentFrom) {
    state.filters.dashboard.recentFrom = dashboardRange.from;
  }

  if (!state.filters.dashboard.recentTo) {
    state.filters.dashboard.recentTo = dashboardRange.to;
  }

  if (!state.filters.congregants.recentFrom) {
    state.filters.congregants.recentFrom = congregantsRange.from;
  }

  if (!state.filters.congregants.recentTo) {
    state.filters.congregants.recentTo = congregantsRange.to;
  }
}

function getCurrentModule_() {
  const view = VIEW_META[state.currentView];
  return view?.module || "dashboard";
}

function getModuleTabs_(moduleId) {
  return (MODULE_TABS[moduleId] || []).filter((item) => canAccessView_(item.view));
}

function getUserPermissions_() {
  const basePermissions = Array.isArray(state.user?.permissions) && state.user.permissions.length
    ? state.user.permissions.slice()
    : ACCESSIBLE_VIEWS.slice();

  if (
    (basePermissions.includes("congregants-new") || basePermissions.includes("welcome-followup"))
    && !basePermissions.includes("welcome-prospects")
  ) {
    basePermissions.push("welcome-prospects");
  }

  return basePermissions;
}

function hasUserPermission_(permission) {
  return getUserPermissions_().includes(permission);
}

function canAccessView_(view) {
  return hasUserPermission_(view);
}

function canUseScrapDelete_() {
  const roleKey = normalizeText(state.user?.role || "");
  return (roleKey === "admin" || roleKey === "administrador") && hasUserPermission_(DELETE_SCRAP_PERMISSION);
}

function getNormalizedUserRole_() {
  return normalizeText(state.user?.role || "");
}

function canUseDashboardPastorReports_() {
  return !["lider", "coordinador"].includes(getNormalizedUserRole_());
}

function getUserScopedDashboardGroups_() {
  const roleKey = getNormalizedUserRole_();
  const userName = normalizeText(state.user?.name || "");

  if (!["lider", "coordinador"].includes(roleKey) || !userName) {
    return [];
  }

  return (Array.isArray(state.catalogs.groups) ? state.catalogs.groups : []).filter((group) => {
    return [group?.leader1Name, group?.leader2Name].some((leaderName) => normalizeText(leaderName || "") === userName);
  });
}

function getDashboardSelectableGroups_(preferredGroups) {
  const rawGroups = Array.isArray(preferredGroups) && preferredGroups.length
    ? preferredGroups
    : (Array.isArray(state.dashboardSeasonMatrix?.groups) && state.dashboardSeasonMatrix.groups.length
      ? state.dashboardSeasonMatrix.groups
      : (Array.isArray(state.catalogs.groups) ? state.catalogs.groups : []));
  const seen = new Set();

  return rawGroups
    .map((group) => {
      const id = String(group?.id ?? group?.groupId ?? "").trim();
      const name = String(group?.name || group?.groupName || resolveGroupName_(id) || "").trim();

      if (!id || seen.has(id)) {
        return null;
      }

      seen.add(id);

      return {
        id,
        name: name || `Grupo ${id}`
      };
    })
    .filter(Boolean)
    .sort((left, right) => normalizeText(left.name).localeCompare(normalizeText(right.name), "es"));
}

function resolveDashboardGroupReportScope_() {
  const selectedGroupId = String(state.filters.dashboard.groupId || "");
  const selectedReportGroupId = String(state.filters.dashboard.reportGroupId || selectedGroupId || "");
  const scopedGroups = getUserScopedDashboardGroups_();
  const scopedIds = scopedGroups.map((group) => String(group?.id || ""));

  if (scopedIds.length) {
    if (selectedReportGroupId && scopedIds.includes(selectedReportGroupId)) {
      return {
        ok: true,
        groupId: selectedReportGroupId,
        groupName: resolveGroupName_(selectedReportGroupId) || selectedReportGroupId,
        source: "selected",
        scopedGroups
      };
    }

    if (scopedIds.length === 1) {
      return {
        ok: true,
        groupId: scopedIds[0],
        groupName: resolveGroupName_(scopedIds[0]) || scopedIds[0],
        source: "role",
        scopedGroups
      };
    }

    return {
      ok: false,
      groupId: "",
      groupName: "",
      source: "role",
      scopedGroups,
      reason: "Selecciona uno de tus grupos para generar el reporte."
    };
  }

  if (selectedReportGroupId) {
    return {
      ok: true,
      groupId: selectedReportGroupId,
      groupName: resolveGroupName_(selectedReportGroupId) || selectedReportGroupId,
      source: "selected",
      scopedGroups
    };
  }

  return {
    ok: false,
    groupId: "",
    groupName: "",
    source: "manual",
    scopedGroups,
    reason: "Selecciona un grupo para generar el reporte."
  };
}

function getFirstAccessibleView_(views) {
  const allowed = views.find((view) => canAccessView_(view));
  return allowed || "dashboard";
}

function getDefaultViewForModule_(moduleId) {
  const meta = MODULE_META[moduleId];
  const tabs = getModuleTabs_(moduleId);

  if (tabs.length) {
    return tabs[0].view;
  }

  return meta?.defaultView || "dashboard";
}

function ensureAccessibleCurrentView_() {
  if (!state.user || isStudentSession_()) {
    return;
  }

  if (!VIEW_META[state.currentView] || !canAccessView_(state.currentView)) {
    state.currentView = getFirstAccessibleView_(ACCESSIBLE_VIEWS);
  }
}

function renderModuleTabs_(moduleId) {
  const tabs = getModuleTabs_(moduleId);

  if (tabs.length <= 1) {
    return "";
  }

  return `
    <div class="module-tabs" role="tablist" aria-label="Fichas del modulo">
      ${tabs.map((tab) => renderModuleTabButton_(tab)).join("")}
    </div>
  `;
}

function renderModuleTabButton_(tab) {
  const isActive = state.currentView === tab.view || (tab.view === "attendance" && state.currentView === "qr");

  return `
    <button
      class="module-tab-button ${isActive ? "active" : ""}"
      data-action="navigate"
      data-view="${escapeHtml(tab.view)}"
      role="tab"
      aria-selected="${isActive ? "true" : "false"}"
    >
      <strong>${escapeHtml(tab.label)}</strong>
      <small>${escapeHtml(tab.description || "")}</small>
    </button>
  `;
}

function normalizeFormationSection_(value) {
  const cleanValue = String(value || "").trim().toLowerCase();
  return ["route", "cases", "operations", "portal", "levels"].includes(cleanValue) ? cleanValue : "route";
}

function getActiveFormationSection_() {
  state.ui.formationSection = normalizeFormationSection_(state.ui.formationSection);
  return state.ui.formationSection;
}

function clearFormationProfileSelection_(options = {}) {
  state.ui.selectedFormationPersonId = "";
  state.formationProfile = null;
  state.ui.formationProfileLoading = false;
  state.ui.formationProfileLoadingPersonId = "";

  if (!options.keepRecord) {
    state.ui.editingFormationRecordId = "";
  }
}

function cacheStudentPortalByPerson_(personId, portal) {
  const cleanPersonId = String(personId || "").trim();

  if (!cleanPersonId || !portal) {
    return;
  }

  state.studentPortalByPerson[cleanPersonId] = portal;
}

function clearStudentPortalByPersonCache_(personId = "") {
  const cleanPersonId = String(personId || "").trim();

  if (!cleanPersonId) {
    state.studentPortalByPerson = {};
    return;
  }

  delete state.studentPortalByPerson[cleanPersonId];
}

function applyStudentPortalSnapshot_(portal) {
  const cleanPersonId = String(portal?.person?.id || "").trim();

  if (!cleanPersonId || !portal) {
    return;
  }

  state.studentPortal = portal;
  state.loaded.studentPortal = true;
  state.ui.selectedFormationPortalPersonId = cleanPersonId;
  cacheStudentPortalByPerson_(cleanPersonId, portal);
}

function applyPortalAccountToStudentPortal_(personId, account) {
  const cleanPersonId = String(personId || "").trim();

  if (!cleanPersonId || !account) {
    return;
  }

  if (String(state.studentPortal?.person?.id || "") === cleanPersonId) {
    state.studentPortal = {
      ...(state.studentPortal || {}),
      account: {
        ...(state.studentPortal?.account || {}),
        ...account
      }
    };
    cacheStudentPortalByPerson_(cleanPersonId, state.studentPortal);
    return;
  }

  if (state.studentPortalByPerson[cleanPersonId]) {
    state.studentPortalByPerson[cleanPersonId] = {
      ...(state.studentPortalByPerson[cleanPersonId] || {}),
      account: {
        ...(state.studentPortalByPerson[cleanPersonId]?.account || {}),
        ...account
      }
    };
  }
}

function ensureFormationPortalDefaultOffering_() {
  const currentOfferingId = String(state.filters.formationOps.offeringId || state.ui.selectedFormationOfferingId || "").trim();

  if (currentOfferingId) {
    return;
  }

  const offerings = getFilteredFormationOfferings_();
  const preferred = offerings.find((item) => {
    const haystack = normalizeText(`${item?.levelName || ""} ${item?.name || ""}`);
    return haystack.includes("encuentro");
  }) || offerings[0] || null;

  if (!preferred?.id) {
    return;
  }

  state.filters.formationOps.offeringId = String(preferred.id || "");
  state.ui.selectedFormationOfferingId = String(preferred.id || "");
}

function getFormationProfileCacheKey_(personId, seasonId) {
  const cleanPersonId = String(personId || "").trim();
  const cleanSeasonId = String(seasonId || state.filters.formation.seasonId || "").trim();
  return cleanPersonId && cleanSeasonId ? `${cleanPersonId}::${cleanSeasonId}` : "";
}

function getCachedFormationProfile_(personId, seasonId) {
  const cacheKey = getFormationProfileCacheKey_(personId, seasonId);
  return cacheKey ? (state.formationProfilesByKey[cacheKey] || null) : null;
}

function cacheFormationProfile_(profile, personId, seasonId) {
  const resolvedPersonId = String(personId || profile?.person?.id || "").trim();
  const resolvedSeasonId = String(seasonId || state.filters.formation.seasonId || "").trim();
  const cacheKey = getFormationProfileCacheKey_(resolvedPersonId, resolvedSeasonId);

  if (!cacheKey || !profile) {
    return;
  }

  state.formationProfilesByKey[cacheKey] = profile;
}

function clearFormationProfileCache_(personId = "", seasonId = "") {
  const cleanPersonId = String(personId || "").trim();
  const cleanSeasonId = String(seasonId || "").trim();

  if (!cleanPersonId && !cleanSeasonId) {
    state.formationProfilesByKey = {};
    return;
  }

  Object.keys(state.formationProfilesByKey).forEach((cacheKey) => {
    const [cachedPersonId, cachedSeasonId] = cacheKey.split("::");

    if (cleanPersonId && cleanSeasonId) {
      if (cachedPersonId === cleanPersonId && cachedSeasonId === cleanSeasonId) {
        delete state.formationProfilesByKey[cacheKey];
      }
      return;
    }

    if (cleanPersonId && cachedPersonId === cleanPersonId) {
      delete state.formationProfilesByKey[cacheKey];
      return;
    }

    if (cleanSeasonId && cachedSeasonId === cleanSeasonId) {
      delete state.formationProfilesByKey[cacheKey];
    }
  });
}

function setFormationProfileLoading_(loading, personId = "") {
  state.ui.formationProfileLoading = Boolean(loading);
  state.ui.formationProfileLoadingPersonId = loading ? String(personId || "") : "";
}

function getFormationSortedLevels_() {
  return state.formationCatalog
    .slice()
    .sort((left, right) => Number(left.order || 0) - Number(right.order || 0))
    .filter((level) => String(level.status || "ACTIVO").toUpperCase() !== "INACTIVO");
}

function getPreviousFormationLevel_(levelId) {
  const cleanLevelId = String(levelId || "").trim();
  const levels = getFormationSortedLevels_();
  const currentIndex = levels.findIndex((level) => String(level.id || "") === cleanLevelId);

  if (currentIndex <= 0) {
    return null;
  }

  return levels[currentIndex - 1] || null;
}

function getLatestFormationEnrollmentByPersonLevel_(personId, levelId) {
  const cleanPersonId = String(personId || "").trim();
  const cleanLevelId = String(levelId || "").trim();

  if (!cleanPersonId || !cleanLevelId) {
    return null;
  }

  return state.formationEnrollments
    .filter((enrollment) => {
      return String(enrollment?.personId || "").trim() === cleanPersonId
        && String(enrollment?.levelId || "").trim() === cleanLevelId;
    })
    .slice()
    .sort((left, right) => {
      const leftTimestamp = parseDateToTimestamp_(left?.enrolledAt || left?.startDate || left?.endDate, true);
      const rightTimestamp = parseDateToTimestamp_(right?.enrolledAt || right?.startDate || right?.endDate, true);
      return rightTimestamp - leftTimestamp;
    })[0] || null;
}

function canAssignPersonToFormationOffering_(personId, offering) {
  const cleanPersonId = String(personId || "").trim();
  const offeringId = String(offering?.id || "").trim();
  const levelId = String(offering?.levelId || "").trim();

  if (!cleanPersonId || !offeringId || !levelId) {
    return false;
  }

  const latestSameLevelEnrollment = getLatestFormationEnrollmentByPersonLevel_(cleanPersonId, levelId);
  const latestSameLevelStatus = String(latestSameLevelEnrollment?.status || "").trim().toUpperCase();

  if (
    latestSameLevelEnrollment
    && (
      latestSameLevelStatus === "EN_CURSO"
      || latestSameLevelStatus === "ACREDITADO"
    )
  ) {
    return false;
  }

  const previousLevel = getPreviousFormationLevel_(levelId);

  if (!previousLevel) {
    return true;
  }

  const previousEnrollment = getLatestFormationEnrollmentByPersonLevel_(cleanPersonId, previousLevel.id);
  return String(previousEnrollment?.status || "").trim().toUpperCase() === "ACREDITADO";
}

function getFormationPendingEnrollmentCandidate_() {
  const cleanPersonId = String(state.ui.pendingFormationEnrollmentPersonId || "").trim();

  if (!cleanPersonId) {
    return null;
  }

  return state.formationCandidates.find((candidate) => String(candidate?.personId || "").trim() === cleanPersonId) || null;
}

function getAssignableFormationOfferings_(personId) {
  const cleanPersonId = String(personId || "").trim();
  const offerings = getFilteredFormationOfferings_();

  if (!cleanPersonId) {
    return offerings;
  }

  return offerings.filter((offering) => canAssignPersonToFormationOffering_(cleanPersonId, offering));
}

function resolveFormationNextLevelFromLoadedData_(currentLevelName = "", currentStatus = "") {
  const levels = getFormationSortedLevels_();

  if (!levels.length) {
    return null;
  }

  const normalizedLevelName = normalizeText(currentLevelName);
  const currentIndex = levels.findIndex((level) => normalizeText(level.name) === normalizedLevelName);
  const normalizedStatus = String(currentStatus || "").trim().toUpperCase();

  if (currentIndex === -1) {
    return levels[0];
  }

  if (normalizedStatus === "ACREDITADO" && levels[currentIndex + 1]) {
    return levels[currentIndex + 1];
  }

  return levels[currentIndex] || levels[0];
}

function buildFormationProfileFromLoadedData_(personId, seasonId = "") {
  const cleanPersonId = String(personId || "").trim();
  const cleanSeasonId = String(seasonId || state.filters.formation.seasonId || "").trim();

  if (!cleanPersonId) {
    return null;
  }

  const currentCandidate = state.formationCandidates.find((candidate) => {
    return String(candidate?.personId || "").trim() === cleanPersonId
      && (!cleanSeasonId || String(candidate?.seasonId || "").trim() === cleanSeasonId);
  }) || state.formationCandidates.find((candidate) => String(candidate?.personId || "").trim() === cleanPersonId) || null;

  const formationRecords = state.formationRecords
    .filter((record) => {
      return String(record?.personId || "").trim() === cleanPersonId
        && (!cleanSeasonId || String(record?.seasonId || "").trim() === cleanSeasonId);
    })
    .slice()
    .sort((left, right) => {
      const leftTimestamp = parseDateToTimestamp_(
        left?.encounterRegisteredAt || left?.invitedAt || left?.requestedAt || left?.updatedAt || left?.createdAt,
        true
      );
      const rightTimestamp = parseDateToTimestamp_(
        right?.encounterRegisteredAt || right?.invitedAt || right?.requestedAt || right?.updatedAt || right?.createdAt,
        true
      );
      return rightTimestamp - leftTimestamp;
    });

  const latestRecord = formationRecords[0] || null;
  const directoryPerson = state.peopleDirectory.find((person) => String(person?.id || "").trim() === cleanPersonId) || null;
  const fullName = String(
    currentCandidate?.personName
    || directoryPerson?.name
    || directoryPerson?.nombreCompleto
    || latestRecord?.personName
    || "Congregante"
  ).trim();
  const currentLevelName = getFormationDisplayLevelName_({
    currentLevel: currentCandidate?.currentLevel,
    stageLabel: latestRecord?.stageLabel,
    levelName: latestRecord?.levelName,
    nivelFormacionActual: directoryPerson?.nivelFormacionActual,
    formationStatus: currentCandidate?.formationStatus || latestRecord?.status || directoryPerson?.estatusFormacion,
    origin: latestRecord?.origin
  }, getFormationDefaultLevelName_()).trim();
  const currentStatus = String(
    currentCandidate?.formationStatus
    || latestRecord?.status
    || directoryPerson?.estatusFormacion
    || "SIN_PROCESO"
  ).trim();
  const personGroupId = String(
    currentCandidate?.groupId
    || latestRecord?.groupId
    || directoryPerson?.grupo
    || directoryPerson?.groupId
    || ""
  ).trim();

  if (!currentCandidate && !formationRecords.length && !directoryPerson) {
    return null;
  }

  return {
    person: {
      ...(directoryPerson || {}),
      id: cleanPersonId,
      nombreCompleto: fullName,
      nombre: fullName,
      numero: String(
        currentCandidate?.personNumber
        || directoryPerson?.numero
        || latestRecord?.personNumber
        || ""
      ).trim(),
      telefono: String(
        currentCandidate?.personPhone
        || directoryPerson?.telefono
        || directoryPerson?.phone
        || ""
      ).trim(),
      grupo: personGroupId,
      estatusFormacion: currentStatus,
      nivelFormacionActual: currentLevelName
    },
    currentCandidate: currentCandidate ? { ...currentCandidate } : (personGroupId ? {
      personId: cleanPersonId,
      personName: fullName,
      personNumber: String(directoryPerson?.numero || latestRecord?.personNumber || "").trim(),
      personPhone: String(directoryPerson?.telefono || directoryPerson?.phone || "").trim(),
      groupId: personGroupId,
      groupName: String(latestRecord?.groupName || resolveGroupName_(personGroupId) || personGroupId).trim(),
      seasonId: cleanSeasonId,
      formationStatus: currentStatus,
      currentLevel: currentLevelName,
      leaderNotifiedAt: latestRecord?.leaderNotifiedAt || "",
      invitedAt: latestRecord?.invitedAt || "",
      encounterRegisteredAt: latestRecord?.encounterRegisteredAt || ""
    } : null),
    nextLevel: resolveFormationNextLevelFromLoadedData_(currentLevelName, currentStatus),
    records: formationRecords,
    meta: {
      source: "loaded-data"
    }
  };
}

function sortFormationRecords_(records) {
  return (Array.isArray(records) ? records.slice() : []).sort((left, right) => {
    const leftTimestamp = parseDateToTimestamp_(
      left?.encounterRegisteredAt || left?.paymentPaidAt || left?.invitedAt || left?.leaderNotifiedAt || left?.requestedAt,
      true
    );
    const rightTimestamp = parseDateToTimestamp_(
      right?.encounterRegisteredAt || right?.paymentPaidAt || right?.invitedAt || right?.leaderNotifiedAt || right?.requestedAt,
      true
    );

    return rightTimestamp - leftTimestamp;
  });
}

function patchFormationCandidateFromRecord_(candidate, record) {
  if (!candidate || !record || String(candidate.personId || "") !== String(record.personId || "")) {
    return candidate;
  }

  return {
    ...candidate,
    seasonId: record.seasonId || candidate.seasonId,
    groupId: record.groupId || candidate.groupId,
    groupName: record.groupName || candidate.groupName,
    formationStatus: record.status || candidate.formationStatus,
    currentLevel: record.levelName || candidate.currentLevel,
    leaderNotifiedAt: record.leaderNotifiedAt || candidate.leaderNotifiedAt,
    invitedAt: record.invitedAt || candidate.invitedAt,
    encounterRegisteredAt: record.encounterRegisteredAt || candidate.encounterRegisteredAt,
    leaderTelegramStatus: record.leaderTelegramStatus || candidate.leaderTelegramStatus,
    leaderTelegramDetail: record.leaderTelegramDetail || candidate.leaderTelegramDetail,
    leaderTelegramAvailable: record.leaderTelegramAvailable ?? candidate.leaderTelegramAvailable,
    leaderTelegramLinkedCount: record.leaderTelegramLinkedCount ?? candidate.leaderTelegramLinkedCount,
    leaderTelegramBotUsername: record.leaderTelegramBotUsername || candidate.leaderTelegramBotUsername,
    leaderName: record.leaderName || candidate.leaderName,
    leaderPhone: record.leaderPhone || candidate.leaderPhone,
    leaderWhatsappUrl: record.leaderWhatsappUrl || candidate.leaderWhatsappUrl,
    inviteWhatsappUrl: record.inviteWhatsappUrl || candidate.inviteWhatsappUrl
  };
}

function applyFormationRecordToLocalState_(record, extra = {}) {
  if (!record?.id || !record?.personId) {
    return;
  }

  const recordId = String(record.id || "");
  const personId = String(record.personId || "");
  const seasonId = String(record.seasonId || state.filters.formation.seasonId || "");
  const currentRecords = Array.isArray(state.formationRecords) ? state.formationRecords : [];
  const nextRecords = currentRecords.filter((item) => String(item?.id || "") !== recordId);

  nextRecords.unshift(record);
  state.formationRecords = sortFormationRecords_(nextRecords);

  state.formationCandidates = (Array.isArray(state.formationCandidates) ? state.formationCandidates : []).map((candidate) => {
    return patchFormationCandidateFromRecord_(candidate, record);
  });

  if (String(extra.removeCandidatePersonId || "") === personId) {
    state.formationCandidates = state.formationCandidates.filter((candidate) => String(candidate?.personId || "") !== personId);
  }

  if (String(state.formationProfile?.person?.id || "") === personId) {
    const currentProfile = state.formationProfile || {};
    const currentRecordsForProfile = Array.isArray(currentProfile.records) ? currentProfile.records : [];
    const nextProfileRecords = currentRecordsForProfile.filter((item) => String(item?.id || "") !== recordId);

    nextProfileRecords.unshift(record);
    state.formationProfile = {
      ...currentProfile,
      currentCandidate: patchFormationCandidateFromRecord_(currentProfile.currentCandidate || null, record) || currentProfile.currentCandidate || null,
      records: sortFormationRecords_(nextProfileRecords),
      portalAccount: extra.portalAccount
        ? {
          ...(currentProfile.portalAccount || {}),
          ...extra.portalAccount
        }
        : currentProfile.portalAccount
    };
    cacheFormationProfile_(state.formationProfile, personId, seasonId);
  } else if (extra.portalAccount) {
    clearFormationProfileCache_(personId, seasonId);
  }
}

function applyPortalAccountToFormationProfile_(personId, account, options = {}) {
  const cleanPersonId = String(personId || "").trim();
  const seasonId = String(options.seasonId || state.filters.formation.seasonId || "").trim();

  if (!cleanPersonId || !account) {
    return;
  }

  if (String(state.formationProfile?.person?.id || "") === cleanPersonId) {
    state.formationProfile = {
      ...(state.formationProfile || {}),
      portalAccount: {
        ...(state.formationProfile?.portalAccount || {}),
        ...account
      }
    };
    cacheFormationProfile_(state.formationProfile, cleanPersonId, seasonId);
    return;
  }

  clearFormationProfileCache_(cleanPersonId, seasonId);
}

function buildEncounterInviteWhatsappUrlClient_(candidate) {
  const phone = String(candidate?.personPhone || "").replace(/\D+/g, "");

  if (!phone) {
    return "";
  }

  const personName = String(candidate?.personName || "bendiciones").trim();
  const groupName = String(candidate?.groupName || "tu grupo de conexión").trim();
  const leaderName = String(candidate?.leaderName || "tu líder").trim();
  const message = [
    `Hola ${personName}.`,
    "Queremos invitarte al ENCUENTRO como siguiente paso de tu crecimiento en Iglesia Fuertes.",
    `Grupo de conexión: ${groupName}`,
    `Tu líder: ${leaderName}`,
    "Si aceptas participar, responde este mensaje para continuar con tu registro."
  ].join("\n");

  return `https://wa.me/${encodeURIComponent(phone)}?text=${encodeURIComponent(message)}`;
}

function getStudentPortalEntryUrl_() {
  if (typeof window === "undefined" || !window.location) {
    return "";
  }

  const origin = String(window.location.origin || "").trim();
  const pathname = String(window.location.pathname || "").trim();

  return `${origin}${pathname}`;
}

function buildStudentPortalAccessWhatsappUrl_(profile, account) {
  const person = profile?.person || {};
  const cleanPhone = normalizeWhatsappPhone_(person.telefono);
  const username = String(account?.username || person.id || "").trim();
  const temporaryPin = String(account?.temporaryPin || "").trim();
  const fullName = String(person.nombreCompleto || person.nombre || "asistente").trim();
  const portalUrl = getStudentPortalEntryUrl_();

  if (!cleanPhone || !username || !temporaryPin) {
    return "";
  }

  const message = [
    `Hola ${fullName}.`,
    "Tu acceso al Portal del Asistente de Iglesia Fuertes V2 ya está listo.",
    `Usuario: ${username}`,
    `PIN temporal: ${temporaryPin}`,
    portalUrl ? `Ingresa aquí: ${portalUrl}` : "Ingresa al Portal del Asistente desde el sistema.",
    "Ahí podrás revisar tu proceso de formación, materiales y avance."
  ].join("\n");

  return buildWhatsappTextShareUrl_(message, cleanPhone);
}

function isUnknownActionError_(error, actionName = "") {
  if (!(error instanceof ApiError)) {
    return false;
  }

  const code = String(error.code || "").toUpperCase();
  const message = String(error.message || "");

  if (code === "UNKNOWN_ACTION") {
    return !actionName || message.includes(actionName);
  }

  return message.includes("Unknown action:") && (!actionName || message.includes(actionName));
}

function extractUnknownActionName_(error) {
  if (!(error instanceof ApiError)) {
    return "";
  }

  const code = String(error.code || "").toUpperCase();
  const message = String(error.message || "");

  if (code === "UNKNOWN_ACTION") {
    return String(error.details?.action || "").trim();
  }

  const match = message.match(/Unknown action:\s*([A-Za-z0-9._-]+)/i);
  return match ? String(match[1] || "").trim() : "";
}

function buildBackendRouteMissingError_(actionName, label) {
  return new ApiError(
    `Tu backend publicado aun no incluye ${label || actionName}. Actualiza los archivos .gs y vuelve a desplegar la Web App.`,
    "BACKEND_OUTDATED",
    {
      action: actionName
    }
  );
}

function isFormationPortalRepositoryMissingError_(error) {
  const message = String(error?.message || "");
  const code = String(error?.code || "").toUpperCase();

  if (code === "FORMATION_PORTAL_REPOSITORY_MISSING") {
    return true;
  }

  return message.includes("reading 'listOfferings'")
    || message.includes("reading 'listEnrollments'")
    || message.includes("V2_44_FormationPortalRepository.gs");
}

function shouldShowDashboardLoading_() {
  const seasonId = String(state.filters.dashboard.seasonId || getLatestSeason()?.id || "");
  const executiveSeasonId = String(state.dashboardExecutive?.seasonFocus?.id || "");
  const matrixSeasonId = String(state.dashboardSeasonMatrix?.seasonId || "");

  return !state.dashboardExecutive ||
    !state.dashboardSeasonMatrix ||
    executiveSeasonId !== seasonId ||
    matrixSeasonId !== seasonId;
}

function readClientStorageJson_(key) {
  try {
    const raw = localStorage.getItem(key);
    return raw ? JSON.parse(raw) : null;
  } catch (error) {
    return null;
  }
}

function writeClientStorageJson_(key, value) {
  try {
    if (value === null || value === undefined) {
      localStorage.removeItem(key);
      return;
    }

    localStorage.setItem(key, JSON.stringify(value));
  } catch (error) {
    // Ignore storage issues in constrained browsers.
  }
}

function sortWelcomePeopleByDate_(rows) {
  return (Array.isArray(rows) ? rows.slice() : []).sort((left, right) => {
    return parseDateToTimestamp_(right.fechaIngreso, true) - parseDateToTimestamp_(left.fechaIngreso, true);
  });
}

function normalizeWelcomeNewRows_(rows) {
  return sortWelcomePeopleByDate_((Array.isArray(rows) ? rows : [])
    .map((row) => buildWelcomePersonClientDto_(row))
    .filter((row) => String(row?.welcomeStatus || "").toUpperCase() === "NUEVO"));
}

function readWelcomeNewSnapshot_() {
  const payload = readClientStorageJson_(WELCOME_NEW_SNAPSHOT_KEY);

  if (!payload || payload.apiUrl !== state.apiUrl) {
    return null;
  }

  if ((Date.now() - Number(payload.savedAt || 0)) > WELCOME_NEW_SNAPSHOT_MAX_AGE_MS) {
    return null;
  }

  return {
    rows: normalizeWelcomeNewRows_(payload.rows),
    savedAt: Number(payload.savedAt || 0)
  };
}

function persistWelcomeNewSnapshot_(rows) {
  writeClientStorageJson_(WELCOME_NEW_SNAPSHOT_KEY, {
    apiUrl: state.apiUrl,
    savedAt: Date.now(),
    rows: normalizeWelcomeNewRows_(rows)
  });
}

function buildWelcomeNewRowsFromDirectory_() {
  if (!state.loaded.peopleDirectory) {
    return [];
  }

  return sortWelcomePeopleByDate_(state.peopleDirectory
    .map((person) => buildWelcomeFallbackFromDirectory_(person))
    .filter((person) => String(person?.welcomeStatus || "").toUpperCase() === "NUEVO"));
}

function primeWelcomeNewView_() {
  const currentRows = getWelcomeNewPeople_();

  if (currentRows.length || (state.loaded.welcome && Array.isArray(state.welcomePeople) && state.welcomePeople.length)) {
    state.ui.welcomeNewSnapshotSource = "";
    return;
  }

  const snapshot = readWelcomeNewSnapshot_();

  if (snapshot) {
    state.welcomePeople = mergeOptimisticWelcomePeople_(snapshot.rows);
    state.ui.welcomeNewSnapshotSource = "snapshot";
    state.ui.welcomeNewRefreshing = true;
    return;
  }

  const fallbackRows = buildWelcomeNewRowsFromDirectory_();

  if (fallbackRows.length) {
    state.welcomePeople = mergeOptimisticWelcomePeople_(fallbackRows);
    state.ui.welcomeNewSnapshotSource = "directory";
    state.ui.welcomeNewRefreshing = true;
  }
}

function warmWelcomeNewInBackground_() {
  if (!state.user || !canAccessView_("congregants-new")) {
    return;
  }

  if (state.currentView === "congregants-new") {
    return;
  }

  if (String(state.cacheKeys.welcomePeople || "") === "welcomePeople::new" && state.loaded.welcome) {
    return;
  }

  void loadWelcomePeople_({
    showLoading: false,
    scope: "new",
    persistToState: false
  })
    .catch(() => {});
}

function setDashboardHydrationState_(enabled, message = "") {
  state.ui.dashboardHydrating = Boolean(enabled);
  state.ui.dashboardHydratingMessage = enabled
    ? (message || "Preparando Dashboard Iglesia...")
    : "";
}

function scheduleBackgroundWarmers_() {
  if (!state.user) {
    return;
  }

  if (backgroundWarmersTimer) {
    window.clearTimeout(backgroundWarmersTimer);
  }

  backgroundWarmersTimer = window.setTimeout(() => {
    backgroundWarmersTimer = 0;
    void (async () => {
      try {
        warmDashboardExecutiveInBackground_();
        warmCommonDataInBackground_();
        warmWelcomeNewInBackground_();

        await waitForUiPaint_(140);

        await Promise.all([
          canAccessView_("congregants-new") || canAccessView_("welcome-followup") || canAccessView_("welcome-prospects")
            ? loadWelcomePeople_({
              showLoading: false,
              scope: "all"
            })
            : Promise.resolve(),
          canAccessView_("catalogs") || canAccessView_("admin-settings") || canAccessView_("admin-users")
            ? loadCatalogs({
              includeMinistries: true
            })
            : Promise.resolve(),
          canAccessView_("catalogs") || canAccessView_("admin-settings") || canAccessView_("admin-users")
            ? loadTelegramConfig_({
              silentUnsupported: true
            })
            : Promise.resolve()
        ]);

        await waitForUiPaint_(220);

        if (canAccessView_("formation")) {
          await Promise.all([
            state.loaded.groups ? Promise.resolve() : loadGroupsCatalog_(),
            state.loaded.seasons ? Promise.resolve() : refreshSeasons(),
            loadFormationProcesses_({
              showLoading: false
            }),
            loadFormationCatalog_({
              showLoading: false
            })
          ]);
        }
      } catch (error) {
        console.warn("No se pudo precalentar la navegación de módulos.", error);
      }
    })();
  }, 520);
}

function bootstrapApplicationInBackground_(options = {}) {
  const token = ++state.viewLoadToken;
  const targetView = state.currentView;
  const shouldHydrateDashboardInline = targetView === "dashboard";

  if (shouldHydrateDashboardInline) {
    setDashboardHydrationState_(true, options.message || "Preparando Dashboard Iglesia...");
    renderApp();
  }

  void bootstrapApplication({
    showLoading: false,
    force: options.force
  })
    .then(() => {
      if (!state.user || token !== state.viewLoadToken || state.currentView !== targetView) {
        return;
      }

      if (shouldHydrateDashboardInline) {
        setDashboardHydrationState_(false);
      }

      renderApp();
    })
    .catch((error) => {
      if (token !== state.viewLoadToken || state.currentView !== targetView) {
        return;
      }

      if (shouldHydrateDashboardInline) {
        setDashboardHydrationState_(false);
        renderApp();
      }

      handleError(error);
    });
}

function loadViewDataInBackground_(view) {
  const token = ++state.viewLoadToken;
  const targetView = view || state.currentView;
  const shouldHydrateDashboardInline = targetView === "dashboard" && shouldShowDashboardLoading_();

  if (shouldHydrateDashboardInline) {
    setDashboardHydrationState_(true, "Actualizando Dashboard Iglesia...");
    renderApp();
  }

  void loadCurrentViewData({
    showLoading: false
  })
    .then(() => {
      if (!state.user || token !== state.viewLoadToken || state.currentView !== targetView) {
        return;
      }

      if (targetView === "dashboard") {
        setDashboardHydrationState_(false);
      }

      renderApp();
    })
    .catch((error) => {
      if (token !== state.viewLoadToken || state.currentView !== targetView) {
        return;
      }

      if (targetView === "dashboard") {
        setDashboardHydrationState_(false);
        renderApp();
      }

      handleError(error);
    });
}

function renderApp() {
  if (!state.user) {
    root.innerHTML = `
      ${renderLoginView()}
      ${renderSystemConfirmationDialog_()}
    `;
    schedulePostRenderSync_();
    return;
  }

  if (isStudentSession_()) {
    root.innerHTML = `
      ${renderStudentPortalView_()}
      ${renderSystemConfirmationDialog_()}
    `;
    schedulePostRenderSync_();
    return;
  }

  ensureAccessibleCurrentView_();

  const view = VIEW_META[state.currentView] || VIEW_META.dashboard;
  const currentModule = getCurrentModule_();
  const moduleMeta = MODULE_META[currentModule] || MODULE_META.dashboard;
  const apiDescriptor = describeApiUrl(state.apiUrl);
  const apiHost = describeApiHost(state.apiUrl);
  const mobileNavOpen = Boolean(state.ui.mobileNavOpen);

  root.innerHTML = `
    <div class="app-shell view-${escapeHtml(state.currentView)} ${mobileNavOpen ? "app-shell-nav-open" : ""}">
      <button
        class="mobile-nav-backdrop ${mobileNavOpen ? "visible" : ""}"
        data-action="close-mobile-nav"
        aria-label="Cerrar menu"
      ></button>

      ${renderMobileAppBar_(view)}

      <aside class="sidebar ${mobileNavOpen ? "is-open" : ""}">
        <div class="sidebar-inner">
          <div class="sidebar-mobile-head">
            <div class="sidebar-mobile-copy">
              <span class="sidebar-mobile-label">Navegacion</span>
              <strong>${escapeHtml(APP_CONFIG.appName)}</strong>
            </div>
            <button class="btn btn-ghost sidebar-close-button" data-action="close-mobile-nav">Cerrar</button>
          </div>

          <div class="sidebar-brand">
            <img src="assets/logo-fuertes.png" alt="Fuertes">
            <p>${escapeHtml(APP_CONFIG.appName)}<br>Control ministerial, asistencia y seguimiento.</p>
          </div>

          <nav class="sidebar-nav">
            ${Object.keys(MODULE_META).map((moduleId) => renderNavButton(moduleId)).filter(Boolean).join("")}
          </nav>

          <div class="sidebar-foot">
            <strong>${escapeHtml(state.user.name || "Usuario")}</strong>
            <span>${escapeHtml(state.user.role || "SIN ROL")}</span>
            <div class="actions-row">
              <button class="btn btn-secondary" data-action="refresh-app">Actualizar</button>
              <button class="btn btn-ghost" data-action="logout">Salir</button>
            </div>
          </div>
        </div>
      </aside>

      <main class="workspace">
        <header class="topbar">
          <div class="topbar-copy">
            <span class="eyebrow">${escapeHtml(moduleMeta.title)}</span>
            <h1>${escapeHtml(view.title)}</h1>
            <p>${escapeHtml(view.subtitle)}</p>
          </div>

          <div class="topbar-actions">
            <div class="topbar-meta" title="${escapeHtml(state.apiUrl)}">
              <span class="topbar-meta-label">API conectada</span>
              <strong class="topbar-meta-value">${escapeHtml(apiHost)}</strong>
              <small class="topbar-meta-copy">${escapeHtml(apiDescriptor)}</small>
            </div>
            <button class="btn btn-ghost" data-action="refresh-app">Actualizar</button>
          </div>
        </header>

        ${renderModuleTabs_(currentModule)}

        ${renderCurrentView()}
      </main>

      ${renderMobileTabBar_()}
    </div>

    ${renderSystemConfirmationDialog_()}
    ${renderWelcomeActionModal_()}
  `;

  schedulePostRenderSync_();
}

function renderSystemConfirmationDialog_() {
  const confirmation = state.ui.confirmation;

  if (!confirmation) {
    return "";
  }

  return `
    <div class="system-modal-backdrop">
      <section class="system-modal-card" role="dialog" aria-modal="true" aria-labelledby="system-modal-title">
        <div class="panel-head">
          <div>
            <h2 id="system-modal-title">${escapeHtml(confirmation.title || "Confirmar accion")}</h2>
            <p>${escapeHtml(confirmation.copy || "Revisa los detalles antes de continuar.")}</p>
          </div>
          <span class="pill ${escapeHtml(confirmation.tone === "danger" ? "warning" : "dark")}">${escapeHtml(confirmation.badge || "Confirmacion")}</span>
        </div>

        ${confirmation.notes && confirmation.notes.length ? `
          <div class="system-modal-notes">
            ${confirmation.notes.map((note) => `<span class="context-item">${escapeHtml(note)}</span>`).join("")}
          </div>
        ` : ""}

        <div class="actions-row">
          <button class="btn btn-ghost" data-action="cancel-system-confirmation">${escapeHtml(confirmation.cancelLabel || "Cancelar")}</button>
          <button class="btn ${confirmation.tone === "danger" ? "btn-danger" : "btn-primary"}" data-action="confirm-system-action">${escapeHtml(confirmation.confirmLabel || "Confirmar")}</button>
        </div>
      </section>
    </div>
  `;
}

function renderWelcomeActionModal_() {
  const activeModal = state.ui.welcomeModal;

  if (!activeModal) {
    return "";
  }

  if (activeModal.kind === "prospect-feedback") {
    const feedbackState = getWelcomeProspectFeedbackModalState_();

    if (!feedbackState) {
      return "";
    }

    const {
      person,
      group,
      actionDate,
      notes,
      leaderTargets,
      selectedTargetIndex,
      selectedTarget
    } = feedbackState;
    const workflow = getWelcomeProspectWorkflowState_(person);
    const hasTargets = leaderTargets.length > 0;

    return `
      <div class="system-modal-backdrop">
        <section class="system-modal-card welcome-prospect-modal" role="dialog" aria-modal="true" aria-labelledby="welcome-feedback-modal-title">
          <div class="panel-head">
            <div>
              <h2 id="welcome-feedback-modal-title">WhatsApp interno al líder</h2>
              <p>Registra la retroalimentación de Bienvenida en la bitácora y abre WhatsApp listo para contactar al liderazgo del grupo.</p>
            </div>
            <span class="pill dark">${escapeHtml(workflow.stage === "PENDING" ? "Pendiente por registrar" : workflow.label)}</span>
          </div>

          <div class="summary-stack welcome-prospect-modal-summary" style="margin-bottom: 16px;">
            <div class="summary-box welcome-prospect-summary-box">
              <span class="status-chip neutral">Prospecto</span>
              <strong>${escapeHtml(person.nombreCompleto || person.nombre || "Sin nombre")}</strong>
              <span>${escapeHtml(person.numero || "-")} | QR ${escapeHtml(person.id || "-")} | ${escapeHtml(person.telefono || "Sin teléfono")}</span>
            </div>
            <div class="summary-box welcome-prospect-summary-box">
              <span class="status-chip neutral">Grupo actual</span>
              <strong>${escapeHtml(group?.name || person.suggestedGroupName || "Sin grupo asignado")}</strong>
              <span>${escapeHtml(getWelcomeLeaderContactSummary_(person))}</span>
            </div>
            <div class="summary-box welcome-prospect-summary-box">
              <span class="status-chip neutral">Último aviso</span>
              <strong>${escapeHtml(formatDate(person.prospectAlertAt) || "Sin fecha")}</strong>
              <span>${escapeHtml(person.prospectAlertStatus || "Telegram pendiente o no registrado")}</span>
            </div>
            <div class="summary-box welcome-prospect-summary-box">
              <span class="status-chip ${escapeHtml(hasTargets ? "success" : "warning")}">Canal interno</span>
              <strong>${escapeHtml(hasTargets ? "WhatsApp disponible" : "Falta WhatsApp líder")}</strong>
              <span>${escapeHtml(hasTargets
                ? (selectedTarget ? `${selectedTarget.name || "Líder"}${selectedTarget.phone ? ` · ${selectedTarget.phone}` : ""}` : "Selecciona destinatario")
                : "Configura al menos un teléfono de líder en Catálogos para usar este canal.")}</span>
            </div>
          </div>

          <form id="welcome-prospect-feedback-form">
            <input type="hidden" name="personId" value="${escapeHtml(person.id || "")}">
            <div class="field-grid two">
              <div class="field">
                <label for="welcome-prospect-feedback-date">Fecha de contacto interno</label>
                <input id="welcome-prospect-feedback-date" name="actionDate" type="date" value="${escapeHtml(actionDate)}">
              </div>
              <div class="field">
                <label for="welcome-prospect-feedback-target">Enviar a</label>
                <select id="welcome-prospect-feedback-target" name="targetIndex" ${hasTargets ? "" : "disabled"}>
                  ${leaderTargets.length
                    ? leaderTargets.map((target, index) => `
                      <option value="${escapeHtml(String(index))}" ${index === selectedTargetIndex ? "selected" : ""}>
                        ${escapeHtml(target.name || `Líder ${index + 1}`)}${target.phone ? ` · ${escapeHtml(target.phone)}` : ""}
                      </option>
                    `).join("")
                    : `<option value="0" selected>Sin líderes con WhatsApp</option>`}
                </select>
              </div>
              <div class="field" style="grid-column: 1 / -1;">
                <label for="welcome-prospect-feedback-notes">Mensaje interno de Bienvenida</label>
                <textarea id="welcome-prospect-feedback-notes" name="notes" rows="4" placeholder="Ejemplo: El prospecto sí respondió, pero todavía no confirma si asistirá al grupo este viernes.">${escapeHtml(notes)}</textarea>
              </div>
            </div>

            <div class="summary-box welcome-prospect-fallback-box tone-neutral" style="margin-top: 18px;">
              <span class="status-chip neutral">Bitácora pastoral</span>
              <strong>Este contacto también quedará guardado</strong>
              <span>Se registra quién lo envió, la fecha y el contexto compartido entre Bienvenida y Grupos de Conexión.</span>
            </div>

            <div class="actions-row welcome-prospect-modal-actions" style="margin-top: 18px;">
              <button class="btn btn-primary" type="submit" ${hasTargets ? "" : "disabled"}>Guardar y abrir WhatsApp</button>
              <button class="btn btn-ghost" type="button" data-action="close-welcome-modal">Cerrar</button>
            </div>
          </form>
        </section>
      </div>
    `;
  }

  const modalState = getWelcomeProspectModalState_();

  if (!modalState) {
    return "";
  }

  const { person, groupId, suggestedAt, notes, leaderTargets } = modalState;
  const workflow = getWelcomeProspectWorkflowState_(person);
  const telegramUi = getWelcomeProspectTelegramUiState_(person, workflow, modalState.modal);
  const pillTone = ["success", "warning", "danger", "dark", "neutral"].includes(String(workflow.tone || ""))
    ? String(workflow.tone || "")
    : "neutral";

  return `
    <div class="system-modal-backdrop">
      <section class="system-modal-card welcome-prospect-modal" role="dialog" aria-modal="true" aria-labelledby="welcome-modal-title">
        <div class="panel-head">
          <div>
            <h2 id="welcome-modal-title">Prospecto GC</h2>
            <p>Confirma los datos de la persona, elige el grupo correcto y guarda el aviso silencioso al líder por Telegram.</p>
          </div>
          <span class="pill ${escapeHtml(pillTone)}">${escapeHtml(workflow.label)}</span>
        </div>

        <div class="summary-stack welcome-prospect-modal-summary" style="margin-bottom: 16px;">
          <div class="summary-box welcome-prospect-summary-box">
            <span class="status-chip neutral">Persona</span>
            <strong>${escapeHtml(person.nombreCompleto || person.nombre || "Sin nombre")}</strong>
            <span>${escapeHtml(person.numero || "-")} | QR ${escapeHtml(person.id || "-")} | ${escapeHtml(person.telefono || "Sin teléfono")}</span>
          </div>
          <div class="summary-box welcome-prospect-summary-box">
            <span class="status-chip neutral">Perfil</span>
            <strong>${escapeHtml(person.estadoCivil || "Sin estado civil")} | Edad ${escapeHtml(String(person.edad || "Sin dato"))}</strong>
            <span>Llegó: ${escapeHtml(formatDate(person.fechaIngreso) || "Sin fecha")} | Nacimiento: ${escapeHtml(formatDate(person.fechaNacimiento) || "Sin fecha")}</span>
          </div>
          <div class="summary-box welcome-prospect-summary-box">
            <span class="status-chip neutral">Estado actual</span>
            <strong>${escapeHtml(workflow.label)}</strong>
            <span>${escapeHtml(workflow.detail)}</span>
          </div>
          <div class="summary-box welcome-prospect-summary-box welcome-prospect-telegram-box tone-${escapeHtml(telegramUi.tone)}">
            <span class="status-chip ${escapeHtml(telegramUi.tone === "dark" ? "neutral" : telegramUi.tone)}">Telegram automático</span>
            <strong>${escapeHtml(telegramUi.label)}</strong>
            <span>${escapeHtml(telegramUi.meta)}</span>
          </div>
        </div>

        <form id="welcome-prospect-form">
          <input type="hidden" name="personId" value="${escapeHtml(person.id || "")}">
          <input type="hidden" name="status" value="PROSPECTO GP">
          <div class="field-grid two">
            <div class="field">
              <label for="welcome-prospect-group">Grupo de conexión sugerido</label>
              <select id="welcome-prospect-group" name="suggestedGroupId" required>
                ${renderOptions(
                  state.catalogs.groups.map((group) => ({
                    value: String(group.id),
                    label: `${group.name} (${group.id})`
                  })),
                  groupId,
                  "Selecciona grupo sugerido"
                )}
              </select>
            </div>
            <div class="field">
              <label for="welcome-prospect-suggested-at">Fecha de sugerencia</label>
              <input id="welcome-prospect-suggested-at" name="actionDate" type="date" value="${escapeHtml(suggestedAt)}">
            </div>
            <div class="field" style="grid-column: 1 / -1;">
              <label>Líder(es) del grupo sugerido</label>
              <div class="context-strip">
                ${(person.leaderContacts || []).length
                  ? person.leaderContacts.map((contact) => `<span class="context-item">${escapeHtml(contact.name || "Sin nombre")}${contact.phone ? ` · ${escapeHtml(contact.phone)}` : ""}</span>`).join("")
                  : `<span class="context-item">Todavía no hay líder configurado para este grupo.</span>`}
              </div>
            </div>
            <div class="field" style="grid-column: 1 / -1;">
              <label for="welcome-prospect-notes">Notas para el líder</label>
              <textarea id="welcome-prospect-notes" name="notes" rows="4" placeholder="Indica contexto, edad, estado civil y lo que el líder debe tomar en cuenta.">${escapeHtml(notes)}</textarea>
            </div>
          </div>

          <div class="actions-row welcome-prospect-modal-actions">
            <button class="btn btn-primary" type="submit">${escapeHtml(workflow.stage === "READY" ? "Guardar · Convertir a PGC" : "Guardar PGC")}</button>
            <button class="btn btn-ghost" type="button" data-action="close-welcome-modal">Cerrar</button>
          </div>
        </form>

        <div class="summary-box welcome-prospect-fallback-box tone-${escapeHtml(telegramUi.allowWhatsappFallback ? "warning" : "neutral")}" style="margin-top: 18px;">
          <span class="status-chip ${escapeHtml(telegramUi.allowWhatsappFallback ? "warning" : "neutral")}">Respaldo manual</span>
          <strong>${escapeHtml(telegramUi.allowWhatsappFallback ? "Usa WhatsApp solo si Telegram falla" : "WhatsApp manual no es necesario por ahora")}</strong>
          <span>${escapeHtml(telegramUi.allowWhatsappFallback
            ? "El prospecto ya quedó guardado, pero Telegram no confirmó el aviso automático. Usa WhatsApp solo como respaldo operativo."
            : "Primero se intenta Telegram. Los botones de WhatsApp se habilitan únicamente cuando Telegram no logra avisar al líder.")}</span>
        </div>

        ${telegramUi.allowWhatsappFallback ? `
        <div class="actions-row welcome-prospect-modal-actions welcome-prospect-fallback-actions" style="margin-top: 18px;">
          ${renderWelcomeProspectLeaderButtons_(leaderTargets)}
        </div>
        ` : ""}
      </section>
    </div>
  `;
}

function getWelcomePersonById_(personId) {
  const cleanPersonId = String(personId || "");

  if (!cleanPersonId) {
    return null;
  }

  if (String(state.welcomeProfile?.person?.id || "") === cleanPersonId) {
    return state.welcomeProfile.person;
  }

  return state.welcomePeople.find((item) => String(item.id || "") === cleanPersonId) || null;
}

function getWelcomeProspectModalState_() {
  const modal = state.ui.welcomeModal;

  if (!modal || modal.kind !== "prospect") {
    return null;
  }

  const sourcePerson = getWelcomePersonById_(modal.personId);

  if (!sourcePerson) {
    return null;
  }

  const shouldPreserveSavedGroup = String(sourcePerson?.welcomeStatus || "").toUpperCase() === "PROSPECTO GP"
    || Boolean(sourcePerson?.prospectWorkflowStarted)
    || Boolean(sourcePerson?.prospectPendingGroupFollowup)
    || Boolean(sourcePerson?.prospectRegisteredInGroup);
  const groupId = String(
    modal.groupId !== undefined
      ? modal.groupId
      : (shouldPreserveSavedGroup ? sourcePerson.suggestedGroupId : "")
  ).trim();
  const suggestedAt = String(modal.suggestedAt || formatDateForInput_(new Date()) || "").trim();
  const notes = modal.notes !== undefined
    ? String(modal.notes || "")
    : String(sourcePerson.lastFollowupNotes || sourcePerson.notasBienvenida || "");
  const previewPerson = buildWelcomePersonClientDto_({
    ...sourcePerson,
    suggestedGroupId: groupId,
    grupoSugerido: groupId,
    suggestedGroupName: groupId ? sourcePerson.suggestedGroupName : "",
    leader: groupId ? sourcePerson.leader : null,
    leaderContacts: groupId ? sourcePerson.leaderContacts : [],
    leaderWhatsappUrl: groupId ? sourcePerson.leaderWhatsappUrl : "",
    leaderWhatsappUrls: groupId ? sourcePerson.leaderWhatsappUrls : []
  });
  const group = state.catalogs.groups.find((item) => String(item.id) === groupId) || null;
  const leaderTargets = buildWelcomeProspectLeaderWhatsappTargets_(previewPerson, group, suggestedAt, notes);

  return {
    modal,
    person: previewPerson,
    groupId,
    group,
    suggestedAt,
    notes,
    leaderTargets
  };
}

function getWelcomeProspectFeedbackModalState_() {
  const modal = state.ui.welcomeModal;

  if (!modal || modal.kind !== "prospect-feedback") {
    return null;
  }

  const sourcePerson = getWelcomePersonById_(modal.personId);

  if (!sourcePerson) {
    return null;
  }

  const groupId = String(sourcePerson?.suggestedGroupId || sourcePerson?.assignedGroupId || "").trim();
  const previewPerson = buildWelcomePersonClientDto_({
    ...sourcePerson,
    suggestedGroupId: groupId,
    grupoSugerido: groupId
  });
  const group = state.catalogs.groups.find((item) => String(item.id) === groupId) || null;
  const actionDate = String(modal.actionDate || formatDateForInput_(new Date()) || "").trim();
  const notes = modal.notes !== undefined
    ? String(modal.notes || "")
    : "";
  const leaderTargets = buildWelcomeProspectLeaderFeedbackWhatsappTargets_(previewPerson, group, actionDate, notes);
  const normalizedTargetIndex = leaderTargets.length
    ? Math.min(Math.max(Number(modal.targetIndex || 0), 0), leaderTargets.length - 1)
    : 0;

  return {
    modal,
    person: previewPerson,
    groupId,
    group,
    actionDate,
    notes,
    leaderTargets,
    selectedTargetIndex: normalizedTargetIndex,
    selectedTarget: leaderTargets[normalizedTargetIndex] || null
  };
}

function getWelcomeProspectTelegramUiState_(person, workflow, modal) {
  const notification = modal?.notification || null;
  const status = String(notification?.status || person?.prospectAlertStatus || "").trim().toUpperCase();
  const detail = String(notification?.detail || person?.prospectAlertDetail || "").trim();
  const sentAt = String(notification?.sentAt || person?.prospectAlertAt || "").trim();
  const sent = notification?.sent === true || status === "ENVIADO";
  const hasSavedProspect = workflow.stage !== "READY";

  if (!hasSavedProspect) {
    return {
      tone: "neutral",
      label: "Telegram se enviará al guardar",
      meta: "Al convertir a PGC el sistema intentará avisar automáticamente al líder por Telegram.",
      sent: false,
      allowWhatsappFallback: false
    };
  }

  if (sent) {
    return {
      tone: "success",
      label: "Telegram enviado al líder",
      meta: sentAt
        ? `Aviso confirmado el ${formatDate(sentAt) || sentAt}.`
        : (detail || "El líder ya recibió el aviso automático por Telegram."),
      sent: true,
      allowWhatsappFallback: false
    };
  }

  const statusMap = {
    PENDIENTE_CONFIGURACION: {
      tone: "warning",
      label: "Telegram pendiente de configuración"
    },
    DESACTIVADO: {
      tone: "warning",
      label: "Telegram desactivado"
    },
    PENDIENTE_VINCULAR: {
      tone: "warning",
      label: "Falta vincular Telegram del líder"
    },
    ERROR: {
      tone: "danger",
      label: "Telegram no pudo avisar al líder"
    }
  };
  const mapped = statusMap[status] || {
    tone: "warning",
    label: "Aviso Telegram pendiente"
  };

  return {
    tone: mapped.tone,
    label: mapped.label,
    meta: detail || "El prospecto ya quedó guardado, pero el aviso automático al líder no se confirmó.",
    sent: false,
    allowWhatsappFallback: true
  };
}

function buildWelcomeProspectLeaderWhatsappTargets_(person, group, suggestedAt, notes) {
  const groupId = String(group?.id || person?.suggestedGroupId || "").trim();
  const groupName = String(group?.name || person?.suggestedGroupName || "").trim();
  const contacts = buildWelcomeLeaderContactsFromGroup_(groupId);

  return contacts
    .map((contact) => {
      const phone = normalizeWhatsappPhone_(contact.phone);

      if (!phone) {
        return null;
      }

      return {
        name: String(contact.name || "Líder").trim(),
        phone: String(contact.phone || "").trim(),
        url: `https://wa.me/${phone}?text=${encodeURIComponent(buildWelcomeProspectLeaderWhatsappText_(person, groupName, suggestedAt, notes, contact.name))}`
      };
    })
    .filter(Boolean);
}

function buildWelcomeProspectLeaderWhatsappText_(person, groupName, suggestedAt, notes, leaderName) {
  const lines = [
    `Hola ${String(leaderName || "líder").trim()},`,
    "",
    "Te compartimos un prospecto enviado por Bienvenida para que puedas contactarlo y registrarlo en tu grupo de conexión.",
    "",
    `Nombre: ${person?.nombreCompleto || person?.nombre || "Sin nombre"}`,
    `Teléfono: ${person?.telefono || "Sin teléfono"}`,
    `Estado civil: ${person?.estadoCivil || "Sin dato"}`,
    `Edad: ${person?.edad || "Sin dato"}`,
    `Fecha de llegada: ${formatDate(person?.fechaIngreso) || "Sin fecha"}`,
    `Fecha de sugerencia: ${formatDate(suggestedAt) || suggestedAt || "Sin fecha"}`,
    `Grupo sugerido: ${groupName || "Sin grupo"}`
  ];

  if (notes) {
    lines.push(`Notas: ${notes}`);
  }

  lines.push("", "Por favor contáctalo y cuando quede integrado realiza su registro en Grupos de Conexión.");
  return lines.join("\n");
}

function buildWelcomeProspectLeaderFeedbackWhatsappTargets_(person, group, actionDate, notes) {
  const groupId = String(group?.id || person?.suggestedGroupId || "").trim();
  const groupName = String(group?.name || person?.suggestedGroupName || "").trim();
  const contacts = buildWelcomeLeaderContactsFromGroup_(groupId);

  return contacts
    .map((contact) => {
      const phone = normalizeWhatsappPhone_(contact.phone);

      if (!phone) {
        return null;
      }

      return {
        name: String(contact.name || "Líder").trim(),
        phone: String(contact.phone || "").trim(),
        url: `https://wa.me/${phone}?text=${encodeURIComponent(buildWelcomeProspectLeaderFeedbackWhatsappText_(person, groupName, actionDate, notes, contact.name))}`
      };
    })
    .filter(Boolean);
}

function buildWelcomeProspectLeaderFeedbackWhatsappText_(person, groupName, actionDate, notes, leaderName) {
  const lines = [
    `Hola ${String(leaderName || "líder").trim()},`,
    "",
    "Te escribimos desde Bienvenida para dar seguimiento interno a este prospecto de Grupos de Conexión.",
    "",
    `Nombre: ${person?.nombreCompleto || person?.nombre || "Sin nombre"}`,
    `Teléfono: ${person?.telefono || "Sin teléfono"}`,
    `Grupo de conexión sugerido: ${groupName || "Sin grupo"}`,
    `Fecha de retroalimentación: ${formatDate(actionDate) || actionDate || "Sin fecha"}`
  ];

  if (notes) {
    lines.push(`Contexto de Bienvenida: ${notes}`);
  }

  lines.push(
    "",
    "¿Nos apoyas confirmando si ya hubo contacto, cómo va el seguimiento y si sigue pendiente el registro en el grupo?"
  );

  return lines.join("\n");
}

function buildWelcomeProspectLeaderFeedbackRecordNote_(person, groupName, actionDate, leaderName, notes) {
  const summary = [
    `Bienvenida preparó WhatsApp interno para ${leaderName || "líder pendiente"}.`,
    `Grupo: ${groupName || "Sin grupo"}.`,
    `Fecha: ${formatDate(actionDate) || actionDate || "Sin fecha"}.`
  ];

  if (person?.telefono) {
    summary.push(`Teléfono del prospecto: ${person.telefono}.`);
  }

  summary.push("Solicitud: confirmar contacto y avance del registro en Grupos de Conexión.");

  if (notes) {
    summary.push(`Contexto enviado: ${notes}`);
  }

  return summary.join(" ");
}

function renderWelcomeProspectLeaderButtons_(targets) {
  if (!targets.length) {
    return `<button class="btn btn-ghost" type="button" disabled>Sin WhatsApp de respaldo</button>`;
  }

  return targets.map((target, index) => `
    <a class="btn btn-ghost" href="${escapeHtml(target.url)}" target="_blank" rel="noreferrer">
      ${escapeHtml(targets.length === 1 ? "WhatsApp respaldo" : `WhatsApp ${target.name || `Líder ${index + 1}`}`)}
    </a>
  `).join("");
}

function openSystemConfirmation_(config) {
  state.ui.confirmation = {
    kind: config.kind || "",
    title: config.title || "Confirmar accion",
    copy: config.copy || "",
    badge: config.badge || "Confirmacion",
    confirmLabel: config.confirmLabel || "Confirmar",
    cancelLabel: config.cancelLabel || "Cancelar",
    tone: config.tone || "primary",
    notes: Array.isArray(config.notes) ? config.notes : [],
    payload: config.payload || {}
  };
  renderApp();
}

function closeSystemConfirmation_() {
  state.ui.confirmation = null;
  renderApp();
}

async function confirmSystemAction_() {
  const confirmation = state.ui.confirmation;

  if (!confirmation) {
    return;
  }

  state.ui.confirmation = null;
  renderApp();

  if (confirmation.kind === "bulk-assign") {
    await executeBulkAssign_();
    return;
  }

  if (confirmation.kind === "deactivate-participant") {
    await executeDeactivateParticipant_(confirmation.payload.participantId);
    return;
  }

  if (confirmation.kind === "welcome-promote-prospect") {
    await promoteWelcomePersonToProspect_(confirmation.payload.personId);
    return;
  }

  if (confirmation.kind === "scrap-delete-season-person") {
    await executeScrapDeleteSeasonPerson_(confirmation.payload.personId, confirmation.payload.seasonId);
    return;
  }

  if (confirmation.kind === "scrap-delete-season") {
    await executeScrapDeleteSeason_(confirmation.payload.seasonId);
    return;
  }

  if (confirmation.kind === "scrap-delete-formation-process") {
    await executeScrapDeleteFormationProcess_(confirmation.payload.processId);
    return;
  }

  if (confirmation.kind === "scrap-delete-person") {
    await executeScrapDeletePerson_(confirmation.payload.personId, confirmation.payload.originView);
    return;
  }

  if (confirmation.kind === "delete-formation-level") {
    await executeDeleteFormationLevel_(confirmation.payload.levelId);
    return;
  }

  if (confirmation.kind === "delete-formation-offering") {
    await executeDeleteFormationOffering_(confirmation.payload.offeringId);
  }
}

function schedulePostRenderSync_() {
  window.requestAnimationFrame(() => {
    void syncRuntimeAfterRender_();
  });
}

async function syncRuntimeAfterRender_() {
  syncResponsiveTablesAfterRender_();
  syncAppShellAfterRender_();

  if (!state.user) {
    stopQrScannerRuntime_();
    return;
  }

  if (isStudentSession_()) {
    stopQrScannerRuntime_();
    return;
  }

  if (state.currentView === "assistants") {
    stopQrScannerRuntime_();
    syncCredentialQrsAfterRender_();
    return;
  }

  const attendanceMode = resolveConnectionAttendanceMode_();
  const shouldKeepQrRuntime = state.currentView === "qr"
    || (state.currentView === "attendance" && attendanceMode !== "manual")
    || isFormationOperationsQrActive_();

  if (!shouldKeepQrRuntime) {
    stopQrScannerRuntime_();
    return;
  }

  if (!state.qrScanner.enabled) {
    stopQrScannerRuntime_(true);
    return;
  }

  await ensureQrScannerStarted_();
}

