async function loadDashboardSessionInsights_(options = {}) {
  await ensureDashboardSessionFilterState_();

  const seasonId = state.filters.dashboard.seasonId;
  const sessionId = state.filters.dashboard.sessionId;
  const cacheKey = `${seasonId}::${sessionId}`;

  if (!seasonId || !sessionId) {
    state.dashboardSessionInsights = null;
    return null;
  }

  if (!options.force && state.dashboardSessionInsights?.key === cacheKey) {
    return state.dashboardSessionInsights;
  }

  const task = async () => {
    if (!state.loaded.peopleDirectory) {
      await loadPeopleDirectory();
    }

    const [sessionGroups, participants, attendances] = await Promise.all([
      ensureSessionGroupsFor(seasonId, sessionId),
      apiGet("participants.list", {
        seasonId,
        sessionId,
        status: "ACTIVO"
      }),
      apiGet("attendances.list", {
        seasonId,
        sessionId
      })
    ]);

    state.dashboardSessionInsights = buildDashboardSessionInsights_({
      seasonId,
      sessionId,
      sessionGroups,
      participants,
      attendances
    });

    return state.dashboardSessionInsights;
  };

  if (options.showLoading === false) {
    return task();
  }

  return withLoading(task, options.message || "Calculando sesion ejecutiva...");
}

async function loadDashboardSeasonMatrix_(options = {}) {
  syncDashboardFilterState_();

  const seasonId = state.filters.dashboard.seasonId || getLatestSeason()?.id || "";
  const cacheKey = String(seasonId || "");
  const loadKey = `dashboardSeasonMatrix::${cacheKey || "none"}`;

  if (!seasonId) {
    state.dashboardSeasonMatrix = null;
    state.cacheKeys.dashboardSeasonMatrix = "";
    return null;
  }

  if (!options.force && state.cacheKeys.dashboardSeasonMatrix === cacheKey && state.dashboardSeasonMatrix) {
    return state.dashboardSeasonMatrix;
  }

  const legacyTask = async () => {
    const sessions = await ensureSessionsForSeason(seasonId);
    const sessionGroupsList = await Promise.all(
      sessions.map((session) => ensureSessionGroupsFor(seasonId, session.id))
    );
    const [participants, attendances] = await Promise.all([
      apiGet("participants.list", {
        seasonId,
        status: "ACTIVO"
      }),
      apiGet("attendances.list", {
        seasonId
      })
    ]);
    const sessionGroupsBySession = {};
    const seasonName = resolveSeasonName_(seasonId) || sessions[0]?.seasonName || "";

    sessions.forEach((session, index) => {
      sessionGroupsBySession[String(session.id)] = sessionGroupsList[index] || [];
    });

    state.dashboardSeasonMatrix = buildDashboardSeasonMatrix_({
      seasonId,
      seasonName,
      sessions,
      sessionGroupsBySession,
      participants,
      attendances
    });
    state.cacheKeys.dashboardSeasonMatrix = cacheKey;
    return state.dashboardSeasonMatrix;
  };

  const task = () => runSharedLoad_(loadKey, async () => {
    let payload;

    if (state.backendSupport.dashboardSeasonMatrixRoute !== false) {
      try {
        payload = await apiGet("dashboard.seasonMatrix", {
          seasonId
        });
        state.backendSupport.dashboardSeasonMatrixRoute = true;
      } catch (error) {
        if (!isUnknownActionError_(error, "dashboard.seasonMatrix")) {
          throw error;
        }

        state.backendSupport.dashboardSeasonMatrixRoute = false;
      }
    }

    if (!payload) {
      return legacyTask();
    }

    state.dashboardSeasonMatrix = {
      ...payload,
      key: String(payload.key || cacheKey),
      seasonId: String(payload.seasonId || seasonId || ""),
      seasonName: payload.seasonName || resolveSeasonName_(seasonId) || ""
    };
    state.cacheKeys.dashboardSeasonMatrix = cacheKey;
    return state.dashboardSeasonMatrix;
  });

  if (options.showLoading === false) {
    return task();
  }

  return withLoading(task, options.message || "Preparando matriz pastoral...");
}

async function ensureSessionGroupsFor(seasonId, sessionId) {
  const cleanSeasonId = String(seasonId || "");
  const cleanSessionId = String(sessionId || "");

  if (!cleanSeasonId || !cleanSessionId) {
    return [];
  }

  const key = `${cleanSeasonId}::${cleanSessionId}`;

  if (!state.sessionGroupsByKey[key]) {
    state.sessionGroupsByKey[key] = await apiGet("sessionGroups.list", {
      seasonId: cleanSeasonId,
      sessionId: cleanSessionId
    });
  }

  return state.sessionGroupsByKey[key];
}

async function syncAllFilters() {
  state.filters.seasons.seasonId = ensureValidSeasonId(state.filters.seasons.seasonId);
  await syncFilterState("participants");
  await syncFilterState("attendance");
  await syncFilterState("qr");
}

async function syncFilterState(viewName) {
  const filter = state.filters[viewName];

  if (!filter) {
    return;
  }

  if (viewName === "attendance") {
    await syncAttendanceFilterState_();
    return;
  }

  filter.seasonId = ensureValidSeasonId(filter.seasonId);

  const sessions = await ensureSessionsForSeason(filter.seasonId);
  if (!sessions.some((item) => item.id === filter.sessionId)) {
    filter.sessionId = sessions[0] ? sessions[0].id : "";
  }

  const groups = await ensureSessionGroupsFor(filter.seasonId, filter.sessionId);
  if (!groups.some((item) => String(item.groupId) === String(filter.groupId))) {
    filter.groupId = groups[0] ? String(groups[0].groupId) : "";
  }
}

function ensureValidSeasonId(currentSeasonId) {
  if (!state.seasons.length) {
    return "";
  }

  const exists = state.seasons.some((season) => season.id === currentSeasonId);
  if (exists) {
    return currentSeasonId;
  }

  return getLatestSeason()?.id || "";
}

async function loadParticipantSeasonAssignments_(options = {}) {
  const seasonId = String(options.seasonId || state.filters.participants.seasonId || "");
  const cacheKey = seasonId;

  if (!seasonId) {
    state.participantSeasonAssignments = {};
    state.cacheKeys.participantSeasonAssignments = "";
    return;
  }

  if (!options.force && state.cacheKeys.participantSeasonAssignments === cacheKey) {
    return;
  }

  const task = async () => {
    const records = await apiGet("participants.list", {
      seasonId,
      status: "ACTIVO"
    });

    state.participantSeasonAssignments = buildParticipantSeasonAssignmentsIndex_(records);
    state.cacheKeys.participantSeasonAssignments = cacheKey;
  };

  if (options.showLoading === false) {
    await task();
    return;
  }

  await withLoading(task, options.message || "Preparando asignaciones de temporada...");
}

async function loadParticipantsData(options = {}) {
  await syncFilterState("participants");

  const filter = state.filters.participants;
  const requestKey = `${filter.seasonId}::${filter.sessionId}::${filter.groupId}`;

  if (!filter.seasonId || !filter.sessionId || !filter.groupId) {
    resetParticipantInteractionState_();
    state.participants = [];
    state.participantContext = null;
    state.participantSeasonAssignments = {};
    state.cacheKeys.participants = "";
    state.cacheKeys.participantSeasonAssignments = "";
    return;
  }

  if (
    !options.force &&
    state.cacheKeys.participants === requestKey &&
    state.participantContext &&
    state.cacheKeys.participantSeasonAssignments === String(filter.seasonId || "")
  ) {
    return;
  }

  const task = async () => {
    const [participants, context] = await Promise.all([
      apiGet("participants.list", {
        seasonId: filter.seasonId,
        sessionId: filter.sessionId,
        groupId: filter.groupId
      }),
      apiGet("participants.groupContext", {
        seasonId: filter.seasonId,
        sessionId: filter.sessionId,
        groupId: filter.groupId
      })
    ]);

    await loadParticipantSeasonAssignments_({
      force: options.force,
      seasonId: filter.seasonId,
      showLoading: false
    });

    state.participants = participants;
    state.participantContext = context;
    state.filters.participants.moveTargets = {};
    state.cacheKeys.participants = requestKey;
  };

  if (options.showLoading === false) {
    await task();
    return;
  }

  await withLoading(task, "Cargando participantes...");
}

async function saveAssistant(rawPayload) {
  const currentAuditUser = getCurrentSystemUserAudit_();
  const payload = sanitizeAssistantPayload_({
    ...rawPayload,
    systemUserName: rawPayload?.systemUserName || currentAuditUser.name,
    systemUserEmail: rawPayload?.systemUserEmail || currentAuditUser.email
  });
  const isWelcomeWorkflow = payload.workflowOrigin === "welcome";

  if (!state.loaded.peopleDirectory && !isWelcomeWorkflow) {
    await loadPeopleDirectory();
  }

  const existing = findExistingPersonMatch_(payload);
  const isEditing = Boolean(payload.id);
  let savedPerson = null;

  if (existing && String(existing.id || "") !== String(payload.id || "")) {
    showToast(
      "Registro duplicado",
      `Ya existe ${existing.nombreCompleto || existing.nombre || "esta persona"} con el mismo nombre y contacto en el folio ${existing.numero || existing.id}.`,
      "warning"
    );
    return;
  }

  await withLoading(async () => {
    savedPerson = await apiPost("servers.save", payload);
    upsertPeopleDirectoryInState_(savedPerson);
    upsertPeopleListInState_(savedPerson);

    if (isWelcomeWorkflow) {
      ensureCongregantsFilterIncludesDate_(savedPerson?.fechaIngreso || payload.fechaIngreso);
      rememberOptimisticWelcomePerson_(savedPerson);
      upsertWelcomePersonInState_(savedPerson);
      state.welcomeProfile = null;
      state.ui.selectedWelcomePersonId = "";
      state.ui.selectedWelcomeFollowupId = "";
    }
  }, isWelcomeWorkflow
    ? (isEditing ? "Actualizando nuevo en Bienvenida..." : "Registrando nuevo en Bienvenida...")
    : (isEditing ? "Actualizando congregante..." : "Guardando congregante..."));

  showToast(
    isWelcomeWorkflow
      ? (isEditing ? "Nuevo actualizado" : "Nuevo registrado")
      : (isEditing ? "Congregante actualizado" : "Congregante guardado"),
    isWelcomeWorkflow
      ? (isEditing
        ? "Los datos del nuevo congregante quedaron actualizados correctamente."
        : "La persona quedó dada de alta en Bienvenida con estatus NUEVO.")
      : (isEditing
        ? "Los datos del congregante ya quedaron actualizados."
        : "La persona ya forma parte del padrón base del sistema."),
    "success"
  );

  schedulePeopleSourcesResync_({
    refreshWelcome: isWelcomeWorkflow,
    refreshProfile: false,
    delayMs: isWelcomeWorkflow ? 3500 : 600
  });

  return savedPerson;
}

function validateWelcomeNewForm_(form) {
  if (!(form instanceof HTMLFormElement)) {
    showToast("Formulario no disponible", "Recarga Bienvenida e intenta nuevamente.", "warning");
    return false;
  }

  const focusField = (field, title, message) => {
    showToast(title, message, "warning");
    field?.focus();

    if (typeof field?.showPicker === "function") {
      try {
        field.showPicker();
      } catch (error) {
        void error;
      }
    }

    return false;
  };

  const nombreField = form.elements.namedItem("nombre");
  const apellidosField = form.elements.namedItem("apellidos");
  const emailField = form.elements.namedItem("email");
  const fechaIngresoField = form.elements.namedItem("fechaIngreso");
  const primerSeguimientoField = form.elements.namedItem("proximoSeguimiento");

  if (!V(nombreField?.value)) {
    return focusField(nombreField, "Falta el nombre", "Escribe el nombre del nuevo asistente antes de registrarlo.");
  }

  if (!V(apellidosField?.value)) {
    return focusField(apellidosField, "Faltan los apellidos", "Escribe los apellidos del nuevo asistente antes de registrarlo.");
  }

  if (V(emailField?.value) && emailField?.validity && !emailField.validity.valid) {
    return focusField(emailField, "Email no válido", "Revisa el correo electrónico antes de guardar el nuevo asistente.");
  }

  if (!V(fechaIngresoField?.value)) {
    if (fechaIngresoField) {
      fechaIngresoField.value = formatDateForInput_(new Date());
    }
  }

  if (!V(primerSeguimientoField?.value)) {
    if (primerSeguimientoField && V(fechaIngresoField?.value)) {
      primerSeguimientoField.value = V(fechaIngresoField.value);
    }
  }

  if (!V(primerSeguimientoField?.value)) {
    return focusField(
      primerSeguimientoField,
      "Falta el primer seguimiento",
      "Selecciona la fecha del primer seguimiento para que Bienvenida pueda dar continuidad al nuevo asistente."
    );
  }

  return true;
}

async function submitWelcomeNewForm_(form) {
  if (!(form instanceof HTMLFormElement)) {
    showToast("Formulario no disponible", "Recarga Bienvenida e intenta nuevamente.", "warning");
    return false;
  }

  if (!validateWelcomeNewForm_(form)) {
    return false;
  }

  const payload = Object.fromEntries(new FormData(form).entries());
  const savedPerson = await saveAssistant(payload);

  if (!savedPerson) {
    return false;
  }

  state.ui.editingWelcomeNewId = "";
  form.reset();
  renderApp();
  scrollToSection_("welcome-new-list");
  return true;
}

function ensureCongregantsFilterIncludesDate_(value) {
  const normalizedDate = String(formatDateForInput_(value) || value || "").trim();

  if (!normalizedDate) {
    return;
  }

  if (!state.filters.congregants.recentFrom || normalizedDate < state.filters.congregants.recentFrom) {
    state.filters.congregants.recentFrom = normalizedDate;
  }

  if (!state.filters.congregants.recentTo || normalizedDate > state.filters.congregants.recentTo) {
    state.filters.congregants.recentTo = normalizedDate;
  }
}

function buildWelcomePersonClientDto_(person) {
  const latestSeason = getLatestSeason();
  const suggestedGroupId = String(person?.suggestedGroupId || person?.grupoSugerido || "").trim();
  const suggestedGroup = state.catalogs.groups.find((group) => String(group.id) === suggestedGroupId) || null;
  const leaderContacts = [];
  const addLeader = (name, phone) => {
    const cleanName = String(name || "").trim();
    const cleanPhone = String(phone || "").trim();

    if (!cleanName && !cleanPhone) {
      return;
    }

    leaderContacts.push({
      id: "",
      name: cleanName,
      phone: cleanPhone,
      type: "LIDER"
    });
  };

  addLeader(suggestedGroup?.leader1Name, suggestedGroup?.leader1Phone);
  addLeader(suggestedGroup?.leader2Name, suggestedGroup?.leader2Phone);

  const welcomeStatus = String(
    person?.welcomeStatus
    || person?.estatusBienvenida
    || (String(person?.tipoPersona || "").toUpperCase() === "NUEVO" ? "NUEVO" : "CONGREGANTE")
  ).toUpperCase();
  const nombre = String(person?.nombre || "").trim();
  const apellidos = String(person?.apellidos || "").trim();
  const nombreCompleto = String(person?.nombreCompleto || `${nombre} ${apellidos}`.trim()).trim();

  return {
    ...person,
    nombre,
    apellidos,
    nombreCompleto,
    welcomeStatus,
    latestSeasonId: latestSeason?.id || "",
    latestSeasonName: latestSeason?.name || "",
    assignedInLatestSeason: Boolean(person?.assignedInLatestSeason),
    assignedGroupId: String(person?.assignedGroupId || "").trim(),
    assignedGroupName: String(person?.assignedGroupName || "").trim(),
    suggestedGroupId,
    suggestedGroupName: suggestedGroup?.name || String(person?.suggestedGroupName || "").trim(),
    leader: leaderContacts[0] || null,
    leaderContacts,
    leaderWhatsappUrl: String(person?.leaderWhatsappUrl || "").trim(),
    leaderWhatsappUrls: Array.isArray(person?.leaderWhatsappUrls) ? person.leaderWhatsappUrls : [],
    lastContactAt: String(person?.lastContactAt || "").trim(),
    lastActionType: String(person?.lastActionType || "").trim(),
    lastFollowupResult: String(person?.lastFollowupResult || "").trim(),
    lastFollowupNotes: String(person?.lastFollowupNotes || person?.notasBienvenida || "").trim(),
    nextFollowUpDate: String(person?.nextFollowUpDate || person?.proximoSeguimiento || "").trim(),
    followupsCount: Number(person?.followupsCount || 0),
    followupTimelineCount: Number(person?.followupTimelineCount || person?.followupsCount || 0),
    prospectWorkflowStarted: Boolean(person?.prospectWorkflowStarted),
    prospectAlertAt: String(person?.prospectAlertAt || "").trim(),
    prospectAlertStatus: String(person?.prospectAlertStatus || "").trim(),
    prospectAlertDetail: String(person?.prospectAlertDetail || "").trim(),
    prospectPendingGroupFollowup: Boolean(person?.prospectPendingGroupFollowup),
    prospectRegisteredInGroup: Boolean(person?.prospectRegisteredInGroup || (person?.prospectWorkflowStarted && person?.assignedInLatestSeason)),
    availableForAssignment: welcomeStatus === "PROSPECTO GP" && !person?.assignedInLatestSeason
  };
}

function buildPeopleListClientDto_(person) {
  const normalizedPerson = person || {};
  return {
    id: String(normalizedPerson.id || "").trim(),
    numero: String(normalizedPerson.numero || "").trim(),
    name: String(normalizedPerson.nombreCompleto || [normalizedPerson.nombre, normalizedPerson.apellidos].filter(Boolean).join(" ") || normalizedPerson.id || "").trim(),
    type: String(normalizedPerson.tipoPersona || "CONGREGANTE").trim(),
    status: String(normalizedPerson.estado || "ACTIVO").trim(),
    groupId: String(normalizedPerson.grupo || "").trim(),
    welcomeStatus: getWelcomeLifecycleStatus_(normalizedPerson)
  };
}

function upsertPeopleDirectoryInState_(person) {
  const nextPerson = {
    ...(person || {})
  };
  const nextId = String(nextPerson.id || "").trim();

  if (!nextId || !state.loaded.peopleDirectory) {
    return;
  }

  state.peopleDirectory = [nextPerson, ...state.peopleDirectory.filter((item) => String(item?.id || "").trim() !== nextId)];
  state.metrics.directoryCount = state.peopleDirectory.length;
}

function upsertPeopleListInState_(person) {
  const nextPerson = buildPeopleListClientDto_(person);
  const nextId = String(nextPerson.id || "").trim();

  if (!nextId || !state.loaded.people) {
    return;
  }

  state.people = [nextPerson, ...state.people.filter((item) => String(item?.id || "").trim() !== nextId)];
  state.metrics.peopleCount = state.people.length;
}

function upsertWelcomePersonInState_(person) {
  const nextPerson = buildWelcomePersonClientDto_(person);
  const nextId = String(nextPerson.id || "").trim();

  if (!nextId) {
    return;
  }

  state.welcomePeople = [nextPerson, ...state.welcomePeople.filter((item) => String(item.id || "") !== nextId)]
    .sort((left, right) => parseDateToTimestamp_(right.fechaIngreso, true) - parseDateToTimestamp_(left.fechaIngreso, true));
  state.loaded.welcome = true;
  state.cacheKeys.welcomePeople = state.cacheKeys.welcomePeople || "welcomePeople::new";
  persistWelcomeNewSnapshot_(state.welcomePeople);
}

function applyWelcomeProfileToLocalState_(profile, options = {}) {
  const nextProfile = profile || null;
  const nextPerson = nextProfile?.person || null;
  const nextId = String(nextPerson?.id || "").trim();

  if (!nextPerson || !nextId) {
    if (options.persistProfile !== false) {
      state.welcomeProfile = nextProfile;
    }
    return;
  }

  rememberOptimisticWelcomePerson_(nextPerson);
  upsertWelcomePersonInState_(nextPerson);
  upsertPeopleListInState_(nextPerson);

  if (state.loaded.peopleDirectory) {
    const existingDirectoryPerson = state.peopleDirectory.find((item) => String(item?.id || "").trim() === nextId) || {};

    upsertPeopleDirectoryInState_({
      ...existingDirectoryPerson,
      ...nextPerson,
      id: nextId,
      nombre: nextPerson.nombre || existingDirectoryPerson.nombre || "",
      apellidos: nextPerson.apellidos || existingDirectoryPerson.apellidos || "",
      nombreCompleto: nextPerson.nombreCompleto || existingDirectoryPerson.nombreCompleto || "",
      telefono: nextPerson.telefono || existingDirectoryPerson.telefono || "",
      email: nextPerson.email || existingDirectoryPerson.email || "",
      fechaIngreso: nextPerson.fechaIngreso || existingDirectoryPerson.fechaIngreso || "",
      proximoSeguimiento: nextPerson.nextFollowUpDate || nextPerson.proximoSeguimiento || existingDirectoryPerson.proximoSeguimiento || "",
      estatusBienvenida: nextPerson.welcomeStatus || nextPerson.estatusBienvenida || existingDirectoryPerson.estatusBienvenida || "",
      notasBienvenida: nextPerson.lastFollowupNotes || nextPerson.notasBienvenida || existingDirectoryPerson.notasBienvenida || ""
    });
  }

  if (options.persistProfile !== false) {
    state.welcomeProfile = nextProfile;
  }
}

function buildOptimisticWelcomeProfileAfterFollowupSave_(response, payload) {
  const sourceProfile = response?.profile || {};
  const savedFollowup = response?.followup || null;
  const previousPerson = getWelcomePersonById_(payload?.personId) || sourceProfile.person || {};
  const sourcePerson = sourceProfile.person || {};
  const followups = Array.isArray(sourceProfile.followups) ? sourceProfile.followups : [];
  const actionType = String(savedFollowup?.actionType || payload?.actionType || "").trim().toUpperCase();
  const isNonPastoralAction = isWelcomeNonPastoralActionType_(actionType);
  const pastoralCountFromTimeline = followups.filter((item) => {
    return !isWelcomeNonPastoralActionType_(item?.actionType);
  }).length;
  const nextFollowupsCount = Math.max(
    Number(sourcePerson.followupsCount || 0),
    pastoralCountFromTimeline,
    Number(previousPerson.followupsCount || 0) + (isNonPastoralAction ? 0 : 1)
  );
  const nextTimelineCount = Math.max(
    Number(sourcePerson.followupTimelineCount || 0),
    Number(sourceProfile.summary?.timelineCount || 0),
    followups.length
  );
  const nextLeaderFeedbackCount = Math.max(
    Number(sourcePerson.leaderFeedbackCount || 0),
    Number(previousPerson.leaderFeedbackCount || 0) + (actionType === "WHATSAPP_LIDER_GC" ? 1 : 0)
  );

  return {
    ...sourceProfile,
    person: {
      ...previousPerson,
      ...sourcePerson,
      followupsCount: nextFollowupsCount,
      followupTimelineCount: nextTimelineCount,
      lastContactAt: String(
        isNonPastoralAction
          ? (sourcePerson.lastContactAt || previousPerson.lastContactAt || "")
          : (savedFollowup?.actionDate || sourcePerson.lastContactAt || previousPerson.lastContactAt || "")
      ).trim(),
      lastActionType: String(
        isNonPastoralAction
          ? (sourcePerson.lastActionType || previousPerson.lastActionType || "")
          : (savedFollowup?.actionType || sourcePerson.lastActionType || previousPerson.lastActionType || "")
      ).trim(),
      lastFollowupResult: String(
        isNonPastoralAction
          ? (sourcePerson.lastFollowupResult || previousPerson.lastFollowupResult || "")
          : (savedFollowup?.result || sourcePerson.lastFollowupResult || previousPerson.lastFollowupResult || "")
      ).trim(),
      lastFollowupNotes: String(
        isNonPastoralAction
          ? (sourcePerson.lastFollowupNotes || previousPerson.lastFollowupNotes || "")
          : (savedFollowup?.notes || sourcePerson.lastFollowupNotes || previousPerson.lastFollowupNotes || "")
      ).trim(),
      nextFollowUpDate: String(
        !isNonPastoralAction && savedFollowup?.nextFollowUpDate !== undefined
          ? savedFollowup.nextFollowUpDate
          : (sourcePerson.nextFollowUpDate || previousPerson.nextFollowUpDate || payload?.nextFollowUpDate || "")
      ).trim(),
      welcomeStatus: String(sourcePerson.welcomeStatus || payload?.status || previousPerson.welcomeStatus || "NUEVO").trim(),
      leaderFeedbackCount: nextLeaderFeedbackCount,
      lastLeaderFeedbackAt: String(
        actionType === "WHATSAPP_LIDER_GC"
          ? (savedFollowup?.actionDate || sourcePerson.lastLeaderFeedbackAt || previousPerson.lastLeaderFeedbackAt || "")
          : (sourcePerson.lastLeaderFeedbackAt || previousPerson.lastLeaderFeedbackAt || "")
      ).trim(),
      lastLeaderFeedbackResult: String(
        actionType === "WHATSAPP_LIDER_GC"
          ? (savedFollowup?.result || sourcePerson.lastLeaderFeedbackResult || previousPerson.lastLeaderFeedbackResult || "")
          : (sourcePerson.lastLeaderFeedbackResult || previousPerson.lastLeaderFeedbackResult || "")
      ).trim(),
      lastLeaderFeedbackNotes: String(
        actionType === "WHATSAPP_LIDER_GC"
          ? (savedFollowup?.notes || sourcePerson.lastLeaderFeedbackNotes || previousPerson.lastLeaderFeedbackNotes || "")
          : (sourcePerson.lastLeaderFeedbackNotes || previousPerson.lastLeaderFeedbackNotes || "")
      ).trim(),
      lastLeaderFeedbackBy: String(
        actionType === "WHATSAPP_LIDER_GC"
          ? (savedFollowup?.systemUserName || sourcePerson.lastLeaderFeedbackBy || previousPerson.lastLeaderFeedbackBy || "")
          : (sourcePerson.lastLeaderFeedbackBy || previousPerson.lastLeaderFeedbackBy || "")
      ).trim()
    },
    summary: {
      ...(sourceProfile.summary || {}),
      followupsCount: nextFollowupsCount,
      timelineCount: nextTimelineCount
    }
  };
}

function prepareLeaderWhatsappWindow_(enabled) {
  if (!enabled) {
    return null;
  }

  try {
    return window.open("", "_blank", "noopener,noreferrer");
  } catch (error) {
    return null;
  }
}

function openLeaderWhatsappWindow_(preparedWindow, url) {
  if (!url) {
    if (preparedWindow && !preparedWindow.closed) {
      preparedWindow.close();
    }
    return false;
  }

  try {
    if (preparedWindow && !preparedWindow.closed) {
      preparedWindow.location.href = url;
      if (typeof preparedWindow.focus === "function") {
        preparedWindow.focus();
      }
      return true;
    }

    const popup = window.open(url, "_blank", "noopener,noreferrer");
    return !!popup;
  } catch (error) {
    return false;
  }
}

async function promoteWelcomePersonToProspect_(personId) {
  const cleanPersonId = String(personId || "");
  const person = state.welcomePeople.find((item) => String(item.id || "") === cleanPersonId)
    || (String(state.welcomeProfile?.person?.id || "") === cleanPersonId ? state.welcomeProfile.person : null);

  if (!cleanPersonId || !person) {
    showToast("Persona no disponible", "Recarga Bienvenida e intenta nuevamente.", "warning");
    return;
  }

  await saveWelcomePerson_({
    personId: cleanPersonId,
    status: "PROSPECTO GP",
    suggestedGroupId: person.suggestedGroupId || "",
    nextFollowUpDate: person.nextFollowUpDate || "",
    notes: person.lastFollowupNotes || person.notasBienvenida || ""
  }, {
    navigateToProspects: false,
    loadingMessage: "Moviendo a Prospecto GC...",
    successTitle: "Persona actualizada",
    successMessage: "La persona pasó a Prospecto GC y ya aparece en el módulo Prospectos."
  });

  if (state.currentView === "welcome-followup") {
    state.welcomeProfile = null;
    state.ui.selectedWelcomePersonId = "";
    state.ui.selectedWelcomeFollowupId = "";
    state.ui.welcomeWorkbenchMode = "";
    renderApp();
  }
}

async function saveWelcomeProspectAssignment_(options = {}) {
  const modalState = getWelcomeProspectModalState_();
  const currentAuditUser = getCurrentSystemUserAudit_();
  let response = null;

  if (!modalState || !modalState.person?.id) {
    showToast("Prospecto no disponible", "Abre nuevamente el modal del prospecto e intenta otra vez.", "warning");
    return false;
  }

  if (!modalState.groupId) {
    showToast("Falta grupo sugerido", "Selecciona el grupo de conexión sugerido antes de guardar.", "warning");
    return false;
  }

  const payload = {
    personId: modalState.person.id,
    actionDate: modalState.suggestedAt || formatDateForInput_(new Date()),
    actionType: "PROSPECTO_GC",
    result: "PENDIENTE_SEGUIMIENTO_GC",
    owner: "BIENVENIDA",
    systemUserName: currentAuditUser.name,
    systemUserEmail: currentAuditUser.email,
    skipTelegram: true,
    skipProfile: true,
    nextFollowUpDate: modalState.person.nextFollowUpDate || "",
    status: "PROSPECTO GP",
    suggestedGroupId: modalState.groupId,
    notes: modalState.notes || ""
  };

  try {
    await withLoading(async () => {
      response = await apiPost("welcome.followups.save", payload);
      applyWelcomeProfileToLocalState_(buildOptimisticWelcomeProfileAfterFollowupSave_(response, payload));
      invalidateWelcomeCache_();
    }, options.loadingMessage || "Guardando y convirtiendo a PGC...");
  } catch (error) {
    throw error;
  }

  state.ui.selectedWelcomePersonId = payload.personId;
  state.ui.selectedWelcomeFollowupId = String(response?.followup?.id || "");
  const initialTelegramNotification = normalizeTelegramNotification_(response?.notification);
  const initialTelegramSent = telegramNotificationWasSent_(initialTelegramNotification);
  state.ui.welcomeModal = {
    kind: "prospect",
    personId: payload.personId,
    groupId: modalState.groupId,
    suggestedAt: payload.actionDate,
    notes: payload.notes,
    notification: initialTelegramSent
      ? initialTelegramNotification
      : {
        sent: false,
        sentAt: "",
        status: "ENVIANDO",
        detail: "Guardado correcto. Enviando aviso por Telegram..."
      }
  };
  schedulePeopleSourcesResync_({
    refreshWelcome: true,
    refreshProfile: true,
    personId: payload.personId,
    delayMs: 450
  });
  renderApp();
  if (initialTelegramSent) {
    showToast(
      options.successTitle || "Prospecto actualizado",
      options.successMessage || initialTelegramNotification.detail || "El prospecto quedó pendiente por registrar y Telegram avisó automáticamente al líder.",
      "success"
    );
    return true;
  }
  showToast(
    options.successTitle || "Prospecto actualizado",
    "El prospecto quedó guardado. Telegram se está enviando en segundo plano.",
    "success"
  );
  void notifyWelcomeProspectLeaderInBackground_(response, payload, {
    successTitle: options.successTitle || "Prospecto actualizado",
    successMessage: options.successMessage || "El prospecto quedó pendiente por registrar y Telegram avisó automáticamente al líder.",
    errorPrefix: "El prospecto quedó guardado, pero"
  });
  return true;
}

function normalizeTelegramNotification_(notification) {
  if (!notification || typeof notification !== "object") {
    return null;
  }
  return {
    sent: notification.sent === true || String(notification.status || "").trim().toUpperCase() === "ENVIADO",
    sentAt: String(notification.sentAt || "").trim(),
    status: String(notification.status || "").trim(),
    detail: String(notification.detail || "").trim()
  };
}

function telegramNotificationWasSent_(notification) {
  return notification?.sent === true
    || String(notification?.status || "").trim().toUpperCase() === "ENVIADO";
}

function isMissingWelcomeProspectNotifyActionError_(error) {
  const message = String(error?.message || "").trim();
  return message.includes("Unknown action: welcome.followups.notifyProspectLeader");
}

async function notifyWelcomeProspectLeaderInBackground_(response, payload, options = {}) {
  const legacyNotification = normalizeTelegramNotification_(response?.notification);
  if (telegramNotificationWasSent_(legacyNotification)) {
    return {
      notification: legacyNotification,
      followup: response?.followup || null
    };
  }

  const followupId = String(response?.followup?.id || "").trim();
  const requestPayload = {
    followupId,
    personId: String(payload?.personId || "").trim(),
    suggestedGroupId: String(payload?.suggestedGroupId || "").trim(),
    actionDate: String(payload?.actionDate || "").trim(),
    notes: String(payload?.notes || "").trim()
  };

  try {
    const notifyResponse = await apiPost("welcome.followups.notifyProspectLeader", requestPayload);
    const telegramNotification = normalizeTelegramNotification_(notifyResponse?.notification);
    const telegramSent = telegramNotificationWasSent_(telegramNotification);

    if (notifyResponse?.followup) {
      const optimisticProfile = buildOptimisticWelcomeProfileAfterFollowupSave_({
        followup: notifyResponse.followup,
        profile: state.welcomeProfile
      }, payload);
      applyWelcomeProfileToLocalState_(optimisticProfile);
      state.ui.selectedWelcomeFollowupId = String(notifyResponse.followup.id || state.ui.selectedWelcomeFollowupId || "");

      if (state.ui.welcomeModal?.kind === "prospect" && String(state.ui.welcomeModal?.personId || "") === String(payload?.personId || "")) {
        state.ui.welcomeModal = {
          ...state.ui.welcomeModal,
          notification: telegramNotification
            ? telegramNotification
            : {
              sent: false,
              sentAt: "",
              status: "ERROR",
              detail: "No se pudo confirmar el envío del aviso por Telegram."
            }
        };
      }
    }

    renderApp();
    showToast(
      telegramSent ? (options.successTitle || "Telegram enviado") : "Aviso pendiente",
      telegramSent
        ? (options.successMessage || "Telegram avisó correctamente al liderazgo.")
        : `${options.errorPrefix || "Se guardó el caso, pero"} ${telegramNotification?.detail || "Telegram no pudo confirmar el envío automático."}`,
      telegramSent ? "success" : "warning"
    );
    return notifyResponse;
  } catch (error) {
    if (isMissingWelcomeProspectNotifyActionError_(error)) {
      if (state.ui.welcomeModal?.kind === "prospect" && String(state.ui.welcomeModal?.personId || "") === String(payload?.personId || "")) {
        state.ui.welcomeModal = {
          ...state.ui.welcomeModal,
          notification: {
            sent: false,
            sentAt: "",
            status: "PENDIENTE",
            detail: "La API publicada aún no incluye el aviso diferido. Si el líder ya recibió Telegram, puedes continuar con el flujo normal."
          }
        };
        renderApp();
      }

      showToast(
        "API pendiente de actualizar",
        "Tu despliegue actual todavía no incluye el aviso diferido de Telegram. Si el mensaje ya llegó al líder, puedes continuar normalmente.",
        "warning"
      );
      return null;
    }

    if (state.ui.welcomeModal?.kind === "prospect" && String(state.ui.welcomeModal?.personId || "") === String(payload?.personId || "")) {
      state.ui.welcomeModal = {
        ...state.ui.welcomeModal,
        notification: {
          sent: false,
          sentAt: "",
          status: "ERROR",
          detail: error?.message || "No se pudo completar el aviso automático por Telegram."
        }
      };
      renderApp();
    }

    showToast(
      "Aviso pendiente",
      `${options.errorPrefix || "Se guardó el caso, pero"} ${error?.message || "Telegram no pudo completar el envío automático."}`,
      "warning"
    );
    return null;
  }
}

async function savePendingProspectGroupAlert_(personId) {
  const cleanPersonId = String(personId || "").trim();
  const person = getWelcomePersonById_(cleanPersonId);
  const draft = getPendingProspectDraft_(person);
  const currentAuditUser = getCurrentSystemUserAudit_();
  const selectedGroupId = String(draft.groupId || "").trim();
  const selectedGroupName = resolveGroupName_(selectedGroupId) || selectedGroupId;
  const previousGroupName = String(person?.suggestedGroupName || "").trim();
  const actionDate = formatDateForInput_(new Date());
  let response = null;

  if (!person || !cleanPersonId) {
    showToast("Prospecto no disponible", "Vuelve a cargar el listado de pendientes e intenta nuevamente.", "warning");
    return false;
  }

  if (!selectedGroupId) {
    showToast("Falta grupo", "Selecciona el grupo de conexión antes de guardar el aviso al líder.", "warning");
    return false;
  }

  const notesParts = [];
  if (draft.groupDirty && previousGroupName && previousGroupName !== selectedGroupName) {
    notesParts.push(`Reasignado desde Grupos de Conexión de ${previousGroupName} a ${selectedGroupName}.`);
  }
  if (String(person.lastFollowupNotes || "").trim()) {
    notesParts.push(String(person.lastFollowupNotes || "").trim());
  } else if (String(person.notasBienvenida || "").trim()) {
    notesParts.push(String(person.notasBienvenida || "").trim());
  }

  const payload = {
    personId: cleanPersonId,
    actionDate,
    actionType: "PROSPECTO_GC",
    result: "PENDIENTE_SEGUIMIENTO_GC",
    owner: "GRUPOS_CONEXION",
    systemUserName: currentAuditUser.name,
    systemUserEmail: currentAuditUser.email,
    skipTelegram: true,
    skipProfile: true,
    nextFollowUpDate: person.nextFollowUpDate || "",
    status: "PROSPECTO GP",
    suggestedGroupId: selectedGroupId,
    notes: notesParts.join(" ").trim()
  };

  await withLoading(async () => {
    response = await apiPost("welcome.followups.save", payload);
    applyWelcomeProfileToLocalState_(buildOptimisticWelcomeProfileAfterFollowupSave_(response, payload));
    invalidateWelcomeCache_();
  }, draft.groupDirty
    ? "Guardando cambio de grupo..."
    : "Guardando grupo...");

  updatePendingProspectDraft_(cleanPersonId, {
    seasonId: draft.seasonId,
    groupId: selectedGroupId
  });

  schedulePeopleSourcesResync_({
    refreshWelcome: true,
    refreshProfile: true,
    personId: cleanPersonId,
    delayMs: 450
  });
  const initialTelegramNotification = normalizeTelegramNotification_(response?.notification);
  if (telegramNotificationWasSent_(initialTelegramNotification)) {
    showToast(
      "Grupo actualizado",
      draft.groupDirty
        ? `El grupo cambió a ${selectedGroupName}. ${initialTelegramNotification.detail || "Telegram ya avisó al nuevo liderazgo."}`
        : (initialTelegramNotification.detail || "Telegram ya avisó al liderazgo de ese grupo."),
      "success"
    );
    renderApp();
    return true;
  }
  showToast(
    "Grupo actualizado",
    draft.groupDirty
      ? `El grupo cambió a ${selectedGroupName}. Telegram se está enviando al nuevo liderazgo.`
      : "El grupo quedó guardado. Telegram se está enviando al liderazgo.",
    "success"
  );
  renderApp();
  void notifyWelcomeProspectLeaderInBackground_(response, payload, {
    successTitle: "Grupo actualizado",
    successMessage: draft.groupDirty
      ? `El prospecto cambió a ${selectedGroupName} y Telegram ya avisó al nuevo liderazgo.`
      : "Telegram confirmó el aviso al liderazgo de ese grupo.",
    errorPrefix: `El grupo quedó guardado en ${selectedGroupName}, pero`
  });
  return true;
}

async function saveWelcomeProspectLeaderFeedback_() {
  const modalState = getWelcomeProspectFeedbackModalState_();
  const currentAuditUser = getCurrentSystemUserAudit_();
  let response = null;
  let whatsappOpened = false;
  const actionDate = modalState?.actionDate || formatDateForInput_(new Date());

  if (!modalState || !modalState.person?.id) {
    showToast("Prospecto no disponible", "Abre nuevamente el caso e intenta otra vez.", "warning");
    return false;
  }

  if (!modalState.groupId) {
    showToast("Falta grupo sugerido", "Primero confirma el grupo de conexión antes de usar el WhatsApp interno.", "warning");
    return false;
  }

  if (!modalState.selectedTarget) {
    showToast("Sin líder con WhatsApp", "Configura al menos un teléfono de líder dentro de Catálogos para habilitar este canal.", "warning");
    return false;
  }

  const preparedWindow = prepareLeaderWhatsappWindow_(true);
  const payload = {
    personId: modalState.person.id,
    actionDate,
    actionType: "WHATSAPP_LIDER_GC",
    result: "WHATSAPP_INTERNO_PREPARADO",
    owner: "BIENVENIDA",
    systemUserName: currentAuditUser.name,
    systemUserEmail: currentAuditUser.email,
    nextFollowUpDate: modalState.person.nextFollowUpDate || "",
    status: "PROSPECTO GP",
    suggestedGroupId: modalState.groupId,
    notes: buildWelcomeProspectLeaderFeedbackRecordNote_(
      modalState.person,
      modalState.group?.name || modalState.person.suggestedGroupName || "",
      actionDate,
      modalState.selectedTarget.name,
      modalState.notes
    )
  };

  await withLoading(async () => {
    response = await apiPost("welcome.followups.save", payload);
    applyWelcomeProfileToLocalState_(response?.profile || null);
    invalidateWelcomeCache_();
    await loadWelcomePeople_({
      force: true,
      showLoading: false
    });
  }, "Guardando retroalimentación interna...");

  whatsappOpened = openLeaderWhatsappWindow_(preparedWindow, modalState.selectedTarget.url);
  state.ui.selectedWelcomePersonId = payload.personId;
  state.ui.selectedWelcomeFollowupId = String(response?.followup?.id || "");
  state.ui.welcomeModal = null;
  renderApp();
  showToast(
    whatsappOpened ? "Canal interno listo" : "Bitácora guardada",
    whatsappOpened
      ? "La retroalimentación quedó registrada y WhatsApp ya se abrió con el mensaje listo para el líder."
      : "La retroalimentación quedó registrada, pero el navegador bloqueó WhatsApp. Intenta nuevamente desde esta misma ficha.",
    whatsappOpened ? "success" : "warning"
  );
  return true;
}

function handleLeaderWhatsappAfterSave_(preparedWindow, profile, enabled) {
  if (!enabled) {
    return;
  }

  const leaderWhatsappTargets = getWelcomeLeaderWhatsappTargets_(profile?.person);
  const leaderWhatsappUrl = String((leaderWhatsappTargets[0] && leaderWhatsappTargets[0].url) || "");

  if (!leaderWhatsappUrl) {
    showToast("Sin WhatsApp del líder", "El caso se guardó, pero el grupo aún no tiene un líder con teléfono válido para abrir WhatsApp.", "warning");
    openLeaderWhatsappWindow_(preparedWindow, "");
    return;
  }

  if (!openLeaderWhatsappWindow_(preparedWindow, leaderWhatsappUrl)) {
    showToast("WhatsApp bloqueado", "El navegador bloqueó la nueva pestaña. Usa el botón de WhatsApp dentro del expediente.", "warning");
  }
}

async function saveWelcomePerson_(rawPayload, options = {}) {
  const payload = {
    personId: V(rawPayload.personId),
    status: V(rawPayload.status),
    suggestedGroupId: V(rawPayload.suggestedGroupId),
    nextFollowUpDate: V(rawPayload.nextFollowUpDate),
    notes: V(rawPayload.notes)
  };
  const shouldOpenLeaderWhatsapp = Boolean(
    options.openLeaderWhatsapp
    && String(payload.status || "").toUpperCase() === "PROSPECTO GP"
  );
  const shouldMoveToProspectStatus = String(payload.status || "").toUpperCase() === "PROSPECTO GP";
  const navigateToProspects = Boolean(options.navigateToProspects);
  const preparedWhatsappWindow = prepareLeaderWhatsappWindow_(shouldOpenLeaderWhatsapp);

  if (!payload.personId) {
    openLeaderWhatsappWindow_(preparedWhatsappWindow, "");
    showToast("Selecciona una persona", "Abre primero un expediente de Bienvenida para poder guardarlo.", "warning");
    return;
  }

  try {
    await withLoading(async () => {
      state.welcomeProfile = await apiPost("welcome.people.update", payload);
      await refreshPeopleSources_();
      invalidateWelcomeCache_();
      await loadWelcomePeople_({
        force: true,
        showLoading: false
      });
    }, options.loadingMessage || "Guardando seguimiento de Bienvenida...");
  } catch (error) {
    openLeaderWhatsappWindow_(preparedWhatsappWindow, "");
    throw error;
  }

  state.ui.selectedWelcomePersonId = payload.personId;
  if (navigateToProspects) {
    state.currentView = "welcome-prospects";
  }
  handleLeaderWhatsappAfterSave_(preparedWhatsappWindow, state.welcomeProfile, shouldOpenLeaderWhatsapp);
  showToast(
    options.successTitle || "Seguimiento guardado",
    options.successMessage || (shouldMoveToProspectStatus
      ? "La persona pasó a Prospectos GC y quedó lista para continuar con la asignación al grupo."
      : "El estatus pastoral y el grupo sugerido quedaron actualizados."),
    "success"
  );
  renderApp();
}

async function saveWelcomeFollowup_(rawPayload) {
  const currentAuditUser = getCurrentSystemUserAudit_();
  const currentScope = String(state.filters.welcome.status || "ALL").toUpperCase();
  const normalizedActionType = V(rawPayload.actionType).toUpperCase();
  const shouldNotifyProspectLeader = normalizedActionType === "PROSPECTO_GC";
  const payload = {
    personId: V(rawPayload.personId),
    actionDate: V(rawPayload.actionDate),
    actionType: normalizedActionType,
    result: V(rawPayload.result),
    owner: V(rawPayload.owner) || currentAuditUser.name || "BIENVENIDA",
    systemUserName: currentAuditUser.name,
    systemUserEmail: currentAuditUser.email,
    nextFollowUpDate: V(rawPayload.nextFollowUpDate),
    status: V(rawPayload.status),
    suggestedGroupId: V(rawPayload.suggestedGroupId),
    notes: V(rawPayload.notes),
    skipTelegram: shouldNotifyProspectLeader,
    skipProfile: shouldNotifyProspectLeader
  };

  if (!payload.personId) {
    showToast("Selecciona una persona", "Abre primero un expediente de Bienvenida para registrar un evento.", "warning");
    return;
  }

  let response = null;

  await withLoading(async () => {
    response = await apiPost("welcome.followups.save", payload);
    state.viewLoadToken += 1;
    applyWelcomeProfileToLocalState_(buildOptimisticWelcomeProfileAfterFollowupSave_(response, payload));
    state.ui.selectedWelcomeFollowupId = String(
      response?.followup?.id
      || state.welcomeProfile?.followups?.[0]?.id
      || ""
    );
  }, "Registrando evento de Bienvenida...");

  state.ui.selectedWelcomePersonId = payload.personId;
  if (currentScope === "SIN_SEGUIMIENTO") {
    state.filters.welcome.status = "CON_SEGUIMIENTO";
  }
  state.ui.welcomeWorkbenchMode = "";
  schedulePeopleSourcesResync_({
    refreshWelcome: true,
    refreshProfile: true,
    personId: payload.personId,
    delayMs: 450
  });
  if (shouldNotifyProspectLeader) {
    const initialTelegramNotification = normalizeTelegramNotification_(response?.notification);
    if (telegramNotificationWasSent_(initialTelegramNotification)) {
      showToast(
        "Aviso enviado",
        initialTelegramNotification.detail || "Telegram avisó correctamente al liderazgo del grupo.",
        "success"
      );
      renderApp();
      return false;
    }
    showToast("Prospecto guardado", "La bitácora quedó guardada. Telegram se está enviando en segundo plano.", "success");
    renderApp();
    void notifyWelcomeProspectLeaderInBackground_(response, payload, {
      successTitle: "Aviso enviado",
      successMessage: "Telegram avisó correctamente al liderazgo del grupo.",
      errorPrefix: "La bitácora quedó guardada, pero"
    });
    return false;
  }

  showToast("Evento registrado", "La bitácora de seguimiento ya quedó actualizada.", "success");
  return false;
}

async function saveCatalogGroupForm_(form) {
  if (!(form instanceof HTMLFormElement)) {
    showToast("Formulario no disponible", "Recarga el catálogo de grupos e intenta nuevamente.", "warning");
    return;
  }

  const payload = Object.fromEntries(new FormData(form).entries());
  const name = String(payload.name || "").trim();
  let savedGroup = null;

  if (!name) {
    const nameField = form.querySelector("[name=\"name\"]");
    showToast("Falta el nombre", "Escribe el nombre del grupo antes de guardar.", "warning");
    nameField?.focus();
    return;
  }

  payload.name = name;

  await withLoading(async () => {
    savedGroup = await apiPost("catalog.groups.save", payload);
    await loadTelegramConfig_({
      force: true
    });
    await loadGroupsCatalog_({
      force: true
    });
  }, payload.id ? "Actualizando grupo..." : "Creando grupo...");

  state.ui.editingGroupId = String(savedGroup?.id || payload.id || "");
  showToast("Catalogo actualizado", "El grupo quedo guardado correctamente.", "success");
  renderApp();
}

function applyTelegramLinkToLocalGroup_(payload) {
  const groupId = String(payload?.groupId || "").trim();
  const leaderSlot = String(payload?.leaderSlot || "").trim();
  const chatId = String(payload?.chatId || "").trim();

  if (!groupId || !leaderSlot || !chatId || !Array.isArray(state.catalogs.groups) || !state.catalogs.groups.length) {
    return;
  }

  state.catalogs.groups = state.catalogs.groups.map((group) => {
    if (String(group?.id || "") !== groupId) {
      return group;
    }

    const updatedGroup = {
      ...group
    };

    if (leaderSlot === "1") {
      updatedGroup.leader1TelegramChatId = chatId;
      updatedGroup.leader1TelegramLinked = true;
    } else if (leaderSlot === "2") {
      updatedGroup.leader2TelegramChatId = chatId;
      updatedGroup.leader2TelegramLinked = true;
    }

    return updatedGroup;
  });
}

function applyTelegramLinksToLocalGroups_(items) {
  const rows = Array.isArray(items) ? items : [];

  rows.forEach((item) => {
    applyTelegramLinkToLocalGroup_(item);
  });
}

async function processPeopleImportFile_(file) {
  await withLoading(async () => {
    ensureXlsxLoaded_();
    const rows = await readWorkbookRows_(file);
    const preparedRows = prepareImportedPeopleRows_(rows);

    state.peopleImport.fileName = file.name;
    state.peopleImport.rows = preparedRows;
    state.peopleImport.summary = summarizePreparedPeopleRows_(preparedRows);
    state.peopleImport.progress = null;
  }, "Leyendo archivo de importacion...");

  showToast("Archivo cargado", `Se prepararon ${state.peopleImport.summary?.totalRows || 0} filas para revision.`, "success");
}

async function importPreparedPeopleRows_() {
  const validRows = state.peopleImport.rows.filter((row) => !row.errors.length);

  if (!validRows.length) {
    showToast("Sin registros validos", "Carga un archivo con al menos una fila valida antes de importar.", "warning");
    return;
  }

  state.peopleImport.progress = {
    phase: "Importando",
    total: validRows.length,
    processed: 0,
    created: 0,
    updated: 0,
    failed: 0
  };
  renderApp();

  try {
    showLoading("Iniciando importacion...");

    for (const row of validRows) {
      setLoadingMessage_(`Importando fila ${row.rowNumber} de ${row.sourceTotalRows}...`);

      try {
        await apiPost("servers.save", row.payload);
        state.peopleImport.progress.processed += 1;

        if (row.operation === "update") {
          state.peopleImport.progress.updated += 1;
        } else {
          state.peopleImport.progress.created += 1;
        }
      } catch (error) {
        state.peopleImport.progress.processed += 1;
        state.peopleImport.progress.failed += 1;
        row.errors.push(error instanceof Error ? error.message : "No se pudo guardar el registro.");
      }
    }
  } finally {
    hideLoading();
  }

  state.peopleImport.progress.phase = state.peopleImport.progress.failed ? "Importacion completada con observaciones" : "Importacion completada";
  state.peopleImport.summary = summarizePreparedPeopleRows_(state.peopleImport.rows);

  await refreshPeopleSources_();
  renderApp();

  showToast(
    "Importacion finalizada",
    `Creados: ${state.peopleImport.progress.created}, actualizados: ${state.peopleImport.progress.updated}, fallidos: ${state.peopleImport.progress.failed}.`,
    state.peopleImport.progress.failed ? "warning" : "success"
  );
}

