async function saveFormationOffering_(rawPayload) {
  const payload = {
    id: V(rawPayload.id),
    processId: V(rawPayload.processId),
    levelId: V(rawPayload.levelId),
    name: V(rawPayload.name),
    leaderName: V(rawPayload.leaderName),
    leaderPhone: V(rawPayload.leaderPhone),
    startDate: V(rawPayload.startDate),
    totalSessions: V(rawPayload.totalSessions),
    status: V(rawPayload.status),
    description: V(rawPayload.description)
  };

  if (!payload.processId) {
    showToast(
      "Primero crea el proceso",
      "Antes de dar de alta un nivel, primero crea o selecciona el Proceso de Formación principal.",
      "warning"
    );
    return;
  }

  let savedOffering = null;

  await withLoading(async () => {
    savedOffering = await apiPost("formation.offerings.save", payload);
    state.filters.formationOps.processId = savedOffering.processId || payload.processId || state.filters.formationOps.processId;
    state.filters.formationOps.levelId = savedOffering.levelId || state.filters.formationOps.levelId;
    state.filters.formationOps.offeringId = savedOffering.id || "";
    state.ui.selectedFormationOfferingId = savedOffering.id || "";
    state.filters.formationOps.sessionNumber = "1";
    await loadFormationOperationsData_({
      force: true,
      showLoading: false,
      processId: state.filters.formationOps.processId,
      offeringId: savedOffering.id,
      sessionNumber: "1"
    });
  }, payload.id ? "Actualizando nivel en operación..." : "Creando nivel en operación...");

  state.ui.editingFormationOfferingId = "";
  state.ui.formationSection = "levels";
  showToast("Nivel guardado", "El nivel quedó programado dentro del proceso. Ahora ya aparece listo para usarse después en Discipulado.", "success");
  renderApp();
  scrollToSection_("formation-offering-panel");
}

async function saveFormationProcess_(rawPayload) {
  const payload = {
    id: V(rawPayload.id),
    name: V(rawPayload.name),
    startDate: V(rawPayload.startDate),
    status: V(rawPayload.status) || "ACTIVO",
    description: V(rawPayload.description)
  };

  if (!payload.name || !payload.startDate) {
    showToast(
      "Faltan datos",
      "Captura al menos el nombre del proceso y la fecha de inicio para poder guardarlo.",
      "warning"
    );
    return;
  }

  let savedProcess = null;

  await withLoading(async () => {
    savedProcess = await apiPost("formation.processes.save", payload);
    state.ui.editingFormationProcessId = "";
    state.filters.formationOps.processId = savedProcess?.id || "";
    state.filters.formationOps.offeringId = "";
    state.ui.selectedFormationOfferingId = "";
    state.ui.editingFormationOfferingId = "";
    state.qrScanner.result = null;
    state.formationQrActivity = [];
    await loadFormationProcesses_({
      force: true,
      showLoading: false
    });
    await loadFormationOperationsData_({
      force: true,
      showLoading: false,
      processId: state.filters.formationOps.processId,
      sessionNumber: "1"
    });
  }, payload.id ? "Actualizando Proceso de Formación..." : "Creando Proceso de Formación...");

  state.ui.formationSection = "levels";
  showToast(
    "Proceso guardado",
    "El Proceso de Formación ya quedó listo. Ahora crea dentro de él los niveles programados con sus sesiones.",
    "success"
  );
  renderApp();
  scrollToSection_("formation-offering-panel");
}

async function activateFormationAttendanceSession_(offeringId, sessionNumber) {
  const cleanOfferingId = String(offeringId || "").trim();
  const cleanSessionNumber = String(sessionNumber || state.filters.formationOps.sessionNumber || "1").trim();
  let response = null;

  if (!cleanOfferingId) {
    showToast("Selecciona un nivel", "Primero elige el nivel en operación que vas a trabajar.", "warning");
    return;
  }

  await withLoading(async () => {
    response = await apiPost("formation.levelAttendance.activateSession", {
      offeringId: cleanOfferingId,
      sessionNumber: cleanSessionNumber,
      activatedBy: state.user?.name || ""
    });

    state.filters.formationOps.offeringId = cleanOfferingId;
    state.ui.selectedFormationOfferingId = cleanOfferingId;
    state.filters.formationOps.sessionNumber = String(response?.context?.sessionNumber || cleanSessionNumber || "1");
    await loadFormationOperationsData_({
      force: true,
      showLoading: false,
      offeringId: cleanOfferingId,
      sessionNumber: state.filters.formationOps.sessionNumber
    });
  }, "Activando sesión del nivel...");

  renderApp();
  showToast(
    "Sesión activada",
    `${response?.activeSession?.label || `Sesión ${state.filters.formationOps.sessionNumber}`} quedó lista para capturar asistencia.`,
    "success"
  );
}

async function assignFormationEnrollment_(personId) {
  const cleanPersonId = String(personId || "").trim();
  const selectedOffering = getSelectedFormationOffering_();
  const person = state.peopleDirectory.find((item) => String(item.id || "") === cleanPersonId) || null;
  const pendingCandidate = getFormationPendingEnrollmentCandidate_();
  const originSeasonId = resolveFormationOriginSeasonIdForPerson_(cleanPersonId);
  let response = null;

  if (!cleanPersonId || !person) {
    showToast("Congregante no disponible", "Recarga el módulo y vuelve a intentar inscribir a la persona.", "warning");
    return;
  }

  if (!selectedOffering?.id) {
    showToast("Selecciona un nivel", "Primero elige el nivel en operación donde vas a inscribir congregantes.", "warning");
    return;
  }

  try {
    await withLoading(async () => {
      response = await apiPost("formation.enrollment.assign", {
        personId: cleanPersonId,
        offeringId: selectedOffering.id,
        seasonId: originSeasonId,
        enrolledBy: state.user?.name || ""
      });
    }, "Inscribiendo al nivel...");
  } catch (error) {
    if (error instanceof ApiError && String(error.code || "").toUpperCase() === "PREVIOUS_LEVEL_REQUIRED") {
      const previousLevelName = String(error.details?.previousLevelName || "el nivel anterior");
      showToast("Primero acredita el nivel anterior", `Esta persona debe acreditar ${previousLevelName} antes de entrar a ${selectedOffering.levelName || "este nivel"}.`, "warning");
      return;
    }

    if (error instanceof ApiError && String(error.code || "").toUpperCase() === "DUPLICATE_LEVEL_ENROLLMENT") {
      showToast("Ya está inscrito en ese nivel", "La persona ya tiene una inscripción activa o acreditada para este mismo nivel.", "warning");
      return;
    }

    throw error;
  }

  state.filters.formationOps.personSearch = "";
  state.ui.selectedFormationEnrollmentId = response?.enrollment?.id || "";
  await loadFormationOperationsData_({
    force: true,
    showLoading: false,
    offeringId: selectedOffering.id,
    sessionNumber: state.filters.formationOps.sessionNumber
  });

  if (String(state.formationProfile?.person?.id || "") === cleanPersonId) {
    await loadFormationProfile_(cleanPersonId, {
      force: true,
      seasonId: state.filters.formation.seasonId,
      showLoading: false
    });
  }

  if (response?.portal) {
    applyStudentPortalSnapshot_(response.portal);
  } else {
    clearStudentPortalByPersonCache_(cleanPersonId);
  }

  if (response?.record) {
    applyFormationRecordToLocalState_(response.record, {
      portalAccount: response?.account || null,
      removeCandidatePersonId: cleanPersonId
    });
  } else if (pendingCandidate && String(pendingCandidate.personId || "") === cleanPersonId) {
    state.formationCandidates = state.formationCandidates.filter((candidate) => String(candidate?.personId || "") !== cleanPersonId);
  }

  if (pendingCandidate && String(pendingCandidate.personId || "") === cleanPersonId) {
    state.ui.pendingFormationEnrollmentPersonId = "";
  }

  renderApp();
  showToast(
    response?.account?.temporaryPin ? "Inscripción y acceso listos" : "Inscripción guardada",
    response?.account?.temporaryPin
      ? `La persona quedó inscrita. Usuario ${response.account.username} con PIN temporal ${response.account.temporaryPin}. Ya puedes abrir Inscritos y portal para enviarlo por WhatsApp.`
      : `${person.nombreCompleto || person.nombre || "La persona"} ya quedó inscrita a ${selectedOffering.levelName || "este nivel"}.`,
    "success"
  );
}

async function saveFormationLevelAttendance_(form) {
  const offeringId = String(form.offeringId?.value || "").trim();
  const sessionNumber = String(form.sessionNumber?.value || state.filters.formationOps.sessionNumber || "1").trim();
  const currentContext = String(state.formationAttendanceContext?.offering?.id || "") === offeringId
    ? state.formationAttendanceContext
    : null;
  const selects = Array.from(form.querySelectorAll("[data-formation-attendance-person]"));
  const attendances = selects
    .map((element) => ({
      personId: String(element.getAttribute("data-formation-attendance-person") || "").trim(),
      attended: String(element.value || "").trim().toUpperCase()
    }))
    .filter((item) => item.personId && (item.attended === "SI" || item.attended === "NO"));
  let response = null;

  if (!offeringId) {
    showToast("Selecciona un nivel", "Primero elige el nivel en operación para guardar asistencia.", "warning");
    return;
  }

  if (!currentContext?.captureEnabled) {
    showToast("Activa la sesión", "Primero activa la sesión correcta del nivel para proteger el registro de asistencia.", "warning");
    return;
  }

  if (!attendances.length) {
    showToast("Sin cambios", "Marca al menos una asistencia en SI o NO antes de guardar.", "warning");
    return;
  }

  await withLoading(async () => {
    response = await apiPost("formation.levelAttendance.capture", {
      offeringId,
      sessionNumber,
      capturedBy: state.user?.name || "",
      attendances
    });
  }, "Guardando asistencia del nivel...");

  state.filters.formationOps.offeringId = offeringId;
  state.ui.selectedFormationOfferingId = offeringId;
  state.filters.formationOps.sessionNumber = String(response?.sessionNumber || sessionNumber || "1");
  await loadFormationOperationsData_({
    force: true,
    showLoading: false,
    offeringId,
    sessionNumber: state.filters.formationOps.sessionNumber
  });
  renderApp();
  showToast("Asistencia guardada", `Se actualizaron ${response?.updated || 0} y se agregaron ${response?.inserted || 0} registros en la sesión ${state.filters.formationOps.sessionNumber}.`, "success");
}

async function saveFormationEnrollmentEvaluation_(rawPayload) {
  const payload = {
    enrollmentId: V(rawPayload.enrollmentId),
    examScore: V(rawPayload.examScore),
    examApproved: V(rawPayload.examApproved),
    comments: V(rawPayload.comments),
    evaluatedBy: state.user?.name || ""
  };
  let response = null;

  if (!payload.enrollmentId) {
    showToast("Selecciona un inscrito", "Primero elige a la persona que vas a evaluar.", "warning");
    return;
  }

  await withLoading(async () => {
    response = await apiPost("formation.enrollment.evaluate", payload);
  }, "Guardando evaluación...");

  state.ui.selectedFormationEnrollmentId = response?.enrollment?.id || payload.enrollmentId;
  await loadFormationOperationsData_({
    force: true,
    showLoading: false,
    offeringId: state.filters.formationOps.offeringId,
    sessionNumber: state.filters.formationOps.sessionNumber
  });

  if (response?.enrollment?.personId && String(state.formationProfile?.person?.id || "") === String(response.enrollment.personId || "")) {
    await loadFormationProfile_(response.enrollment.personId, {
      force: true,
      seasonId: state.filters.formation.seasonId,
      showLoading: false
    });
  }

  if (response?.portal) {
    applyStudentPortalSnapshot_(response.portal);
  } else if (response?.enrollment?.personId) {
    clearStudentPortalByPersonCache_(response.enrollment.personId);
  }

  renderApp();
  showToast(
    response?.accredited ? "Nivel acreditado" : "Evaluación guardada",
    response?.accredited
      ? "La persona acreditó el nivel y su siguiente paso ya quedó desbloqueado en el portal del asistente."
      : "La evaluación quedó guardada. Recuerda que solo se acredita cuando tiene todas las asistencias y examen aprobado.",
    response?.accredited ? "success" : "warning"
  );
}

async function sendFormationEncounterInvite_(candidate) {
  if (!candidate?.personId) {
    showToast("Selecciona una persona", "No fue posible ubicar el congregante para enviar la invitación.", "warning");
    return;
  }

  if (!candidate.personPhone) {
    showToast("Sin teléfono", "Esta persona no tiene teléfono registrado para preparar el WhatsApp.", "warning");
    return;
  }

  const fastWhatsappUrl = buildEncounterInviteWhatsappUrlClient_(candidate);
  const inviteWindow = fastWhatsappUrl
    ? window.open(fastWhatsappUrl, "_blank", "noopener,noreferrer")
    : window.open("", "_blank");
  let response = null;

  await withLoading(async () => {
    response = await apiPost("formation.encounter.sendInvite", {
      personId: candidate.personId,
      seasonId: candidate.seasonId,
      sentBy: state.user?.name || "",
      inviteWhatsappUrl: fastWhatsappUrl
    });
  }, "Registrando invitación a Encuentro...");

  const portalAccess = response?.portalAccess || null;
  applyFormationRecordToLocalState_(response?.record || null);
  state.ui.selectedFormationPersonId = candidate.personId;
  state.ui.formationSection = "route";
  state.formationProfile = buildFormationProfileFromLoadedData_(candidate.personId, candidate.seasonId) || state.formationProfile;

  if (portalAccess?.account && state.formationProfile) {
    state.formationProfile = {
      ...state.formationProfile,
      portalAccount: {
        ...(state.formationProfile.portalAccount || {}),
        ...portalAccess.account
      }
    };
  }

  if (state.formationProfile) {
    cacheFormationProfile_(state.formationProfile, candidate.personId, candidate.seasonId);
  }

  clearStudentPortalByPersonCache_(candidate.personId);

  renderApp();

  if (!fastWhatsappUrl && response?.whatsappUrl) {
    if (inviteWindow) {
      inviteWindow.location = response.whatsappUrl;
    } else {
      window.open(response.whatsappUrl, "_blank", "noopener,noreferrer");
    }
  } else if (inviteWindow) {
    // Si el enlace rápido ya abrió WhatsApp, no hacemos nada más.
  }

  showToast("Invitación lista", "La fecha de invitación quedó registrada y el WhatsApp del congregante se abrió de inmediato.", "success");
}

async function registerFormationEncounter_(candidate) {
  if (!candidate?.personId) {
    showToast("Selecciona una persona", "No fue posible ubicar el congregante para registrar su Encuentro.", "warning");
    return;
  }

  if (!state.formationProcesses.length) {
    state.ui.formationSection = "levels";
    renderApp();
    showToast(
      "Primero crea el proceso",
      "Antes de inscribir al congregante, crea al menos un Proceso de Formación y su primer nivel programado.",
      "warning"
    );
    scrollToSection_("formation-process-panel");
    return;
  }

  const preferredProcessId = String(state.filters.formationOps.processId || state.formationProcesses[0]?.id || "").trim();
  state.ui.pendingFormationEnrollmentPersonId = candidate.personId;
  state.ui.selectedFormationPersonId = candidate.personId;
  state.ui.formationSection = "operations";
  state.filters.formationOps.processId = preferredProcessId;
  state.filters.formationOps.levelId = "";
  state.filters.formationOps.offeringId = "";
  state.filters.formationOps.personSearch = "";

  await loadFormationOperationsData_({
    force: false,
    showLoading: false,
    processId: preferredProcessId,
    levelId: "",
    offeringId: "",
    sessionNumber: "1"
  });

  const eligibleOfferings = getAssignableFormationOfferings_(candidate.personId);
  const firstEligibleOffering = eligibleOfferings[0] || null;

  if (firstEligibleOffering) {
    state.filters.formationOps.levelId = String(firstEligibleOffering.levelId || "");
    state.filters.formationOps.offeringId = String(firstEligibleOffering.id || "");
    state.ui.selectedFormationOfferingId = String(firstEligibleOffering.id || "");
    syncFormationOperationsSelection_();
  }

  renderApp();

  if (!firstEligibleOffering) {
    state.ui.formationSection = "levels";
    renderApp();
    showToast(
      "Falta nivel habilitado",
      "La persona ya está lista, pero en el proceso seleccionado todavía no existe un nivel disponible para inscribirla. Crea o activa el primer nivel.",
      "warning"
    );
    scrollToSection_("formation-offering-panel");
    return;
  }

  showToast(
    "Paso listo",
    `Ahora confirma el Proceso de Formación y completa la inscripción de ${candidate.personName || "la persona"} en ${firstEligibleOffering.levelName || "el primer nivel"}.`,
    "success"
  );
}

function downloadPeopleTemplate_() {
  const headers = [[
    "NOMBRE",
    "APELLIDOS",
    "EDAD",
    "ESTADO_CIVIL",
    "ANIO_NACIMIENTO",
    "TELEFONO",
    "EMAIL",
    "MINISTERIO1",
    "MINISTERIO2",
    "MINISTERIO3",
    "MINISTERIO4",
    "GRUPO",
    "FECHA",
    "TIPO_PERSONA",
    "FECHA_NACIMIENTO"
  ]];

  if (typeof window.XLSX === "function" || window.XLSX?.utils) {
    const worksheet = window.XLSX.utils.aoa_to_sheet(headers);
    const workbook = window.XLSX.utils.book_new();
    window.XLSX.utils.book_append_sheet(workbook, worksheet, "ASISTENTES");
    window.XLSX.writeFile(workbook, "PLANTILLA_ASISTENTES_V2.xlsx");
    return;
  }

  downloadFallbackTemplateCsv_(headers[0]);
}

function clearPeopleImportState_() {
  state.peopleImport = {
    fileName: "",
    rows: [],
    summary: null,
    progress: null
  };
}

async function addParticipant(personId) {
  const filter = state.filters.participants;
  let createdParticipant = null;
  const assignmentState = getParticipantSeasonAssignmentState_(personId, filter.groupId, getParticipantPersonIdSet_());
  ensureContextReady(filter, "participantes");

  if (assignmentState.blockedByOtherGroup) {
    showToast(
      "Asignacion no permitida",
      buildParticipantConflictToastCopy_(assignmentState.seasonAssignment),
      "warning"
    );
    return;
  }

  try {
    await withLoading(async () => {
      createdParticipant = await apiPost("participants.add", {
        seasonId: filter.seasonId,
        sessionId: filter.sessionId,
        groupId: filter.groupId,
        personId
      });
    }, "Agregando participante...");
  } catch (error) {
    if (isParticipantSeasonConflictError_(error)) {
      showToast("Asignacion no permitida", buildParticipantConflictToastCopy_(error.details), "warning");
      return;
    }

    throw error;
  }

  invalidateDashboardSeasonMatrix_();
  invalidateWelcomeCache_();
  await loadParticipantSeasonAssignments_({
    force: true,
    seasonId: filter.seasonId,
    showLoading: false
  });
  mergeParticipantsIntoCurrentContext_([createdParticipant]);
  showToast("Participante agregado", "La persona ya fue agregada al grupo actual.", "success");
  renderApp();
  focusInputById_("participant-people-search");
}

async function bulkAssignParticipants() {
  const filter = state.filters.participants;
  const diagnostics = getSelectedBulkPeopleDiagnostics_();
  const selectedPeople = diagnostics.selectedPeople;
  const seasonName = resolveSeasonName_(filter.seasonId) || filter.seasonId;
  const groupName = state.participantContext ? state.participantContext.group.name : (resolveGroupName_(filter.groupId) || filter.groupId);
  const sessionCount = getSessions(filter.seasonId).length;
  ensureContextReady(filter, "asignacion masiva");

  if (!selectedPeople.length) {
    showToast("Sin seleccion", "Selecciona al menos una persona para la asignacion masiva.", "warning");
    return;
  }

  if (diagnostics.blockedPeople.length) {
    showToast(
      "Hay conflictos en el lote",
      buildParticipantConflictToastCopy_({
        conflicts: diagnostics.blockedPeople.map((person) => {
          const seasonAssignment = getParticipantSeasonAssignment_(person.id);
          return {
            personId: person.id,
            personName: person.name,
            existingGroupId: seasonAssignment?.groupId || "",
            existingGroupName: seasonAssignment?.groupName || ""
          };
        })
      }),
      "warning"
    );
    return;
  }

  openSystemConfirmation_({
    kind: "bulk-assign",
    title: "Confirmar asignacion masiva",
    copy: `Asignaras ${selectedPeople.length} persona(s) al grupo ${groupName} en las ${sessionCount} sesiones de ${seasonName}.`,
    badge: "Toda la temporada",
    confirmLabel: "Asignar ahora",
    notes: [
      `${selectedPeople.length} personas en el lote`,
      `${sessionCount} sesiones del ciclo`,
      `${groupName} como grupo unico en la temporada`
    ]
  });
}

async function executeBulkAssign_() {
  const filter = state.filters.participants;
  const diagnostics = getSelectedBulkPeopleDiagnostics_();
  const selectedPeople = diagnostics.selectedPeople;
  const sessionCount = getSessions(filter.seasonId).length;
  let assignmentResult = null;

  if (!selectedPeople.length) {
    showToast("Sin seleccion", "El lote actual ya no tiene personas para asignar.", "warning");
    return;
  }

  try {
    await withLoading(async () => {
      assignmentResult = await apiPost("participants.bulkAssign", {
        seasonId: filter.seasonId,
        groupId: filter.groupId,
        people: state.selectedBulkPeople.map((personId) => ({ personId }))
      });
      state.selectedBulkPeople = [];
    }, "Asignando participantes...");
  } catch (error) {
    if (isParticipantSeasonConflictError_(error)) {
      await loadParticipantSeasonAssignments_({
        force: true,
        seasonId: filter.seasonId,
        showLoading: false
      });
      showToast("Asignacion no permitida", buildParticipantConflictToastCopy_(error.details), "warning");
      renderApp();
      return;
    }

    throw error;
  }

  invalidateDashboardSeasonMatrix_();
  invalidateWelcomeCache_();
  await loadParticipantSeasonAssignments_({
    force: true,
    seasonId: filter.seasonId,
    showLoading: false
  });
  mergeParticipantsIntoCurrentContext_((assignmentResult && assignmentResult.inserted) || []);
  showToast(
    "Asignacion completada",
    `Se asignaron ${assignmentResult?.totalPeople || selectedPeople.length} persona(s) a ${sessionCount} sesion(es). En esta sesion quedaron ${state.participants.length} participantes activos.`,
    "success"
  );
  renderApp();
  focusInputById_("participant-bulk-search");
}

async function assignPendingProspectToSeason_(personId, groupId, seasonId) {
  const cleanPersonId = String(personId || "");
  const cleanGroupId = String(groupId || "");
  const cleanSeasonId = String(seasonId || "").trim();
  const sessions = await ensurePendingProspectSeasonGroups_(cleanSeasonId);
  const seasonGroupCoverage = getPendingProspectSeasonGroupCoverage_(cleanSeasonId, cleanGroupId);
  let assignmentResult = null;

  if (!cleanSeasonId) {
    showToast("Selecciona temporada", "Antes de registrar un prospecto define la temporada donde quedará asignado.", "warning");
    return;
  }

  if (!cleanGroupId) {
    showToast("Falta grupo sugerido", "Ese prospecto todavía no tiene grupo de conexión sugerido.", "warning");
    return;
  }

  if (!sessions.length) {
    showToast("Temporada sin sesiones", "La temporada seleccionada no tiene sesiones disponibles para registrar al prospecto.", "warning");
    return;
  }

  if (!seasonGroupCoverage.available) {
    showToast(
      "Grupo fuera de temporada",
      buildPendingProspectMissingGroupCopy_(cleanSeasonId, cleanGroupId, seasonGroupCoverage.missingSessions),
      "warning"
    );
    return;
  }

  try {
    await withLoading(async () => {
      assignmentResult = await apiPost("participants.bulkAssign", {
        seasonId: cleanSeasonId,
        groupId: cleanGroupId,
        people: [{ personId: cleanPersonId }]
      });
    }, "Registrando prospecto en la temporada...");
  } catch (error) {
    if (isParticipantSeasonConflictError_(error)) {
      await loadParticipantSeasonAssignments_({
        force: true,
        seasonId: cleanSeasonId,
        showLoading: false
      });
      showToast("Asignación no permitida", buildParticipantConflictToastCopy_(error.details), "warning");
      renderApp();
      return;
    }

    if (isParticipantSeasonGroupMissingError_(error)) {
      showToast(
        "Grupo fuera de temporada",
        buildPendingProspectMissingGroupCopy_(cleanSeasonId, cleanGroupId),
        "warning"
      );
      renderApp();
      return;
    }

    throw error;
  }

  state.filters.participants.seasonId = cleanSeasonId;
  state.filters.participants.groupId = cleanGroupId;
  state.filters.participants.sessionId = sessions[0]?.id || "";
  clearPendingProspectDraft_(cleanPersonId);
  invalidateDashboardSeasonMatrix_();
  invalidateWelcomeCache_();
  await Promise.all([
    loadParticipantSeasonAssignments_({
      force: true,
      seasonId: cleanSeasonId,
      showLoading: false
    }),
    loadWelcomePeople_({
      force: true,
      showLoading: false
    })
  ]);
  await loadParticipantsData({
    force: true,
    showLoading: false
  });
  showToast(
    "Prospecto registrado",
    `La persona quedó asignada al grupo ${resolveGroupName_(cleanGroupId) || cleanGroupId} durante ${assignmentResult?.sessionCount || sessions.length} sesión(es) de la temporada.`,
    "success"
  );
  renderApp();
  scrollToSection_("participants-roster");
}

async function executeDeactivateParticipant_(participantId) {
  await withLoading(async () => {
    await apiPost("participants.deactivate", {
      participantId
    });
    delete state.filters.participants.moveTargets[participantId];
    invalidateDashboardSeasonMatrix_();
    invalidateWelcomeCache_();
    await loadParticipantsData({
      force: true,
      showLoading: false
    });
  }, "Dando de baja participante...");

  showToast("Participante dado de baja", "La baja se reflejo en toda la temporada.", "success");
  renderApp();
}

async function executeScrapDeleteSeasonPerson_(personId, seasonId) {
  const cleanPersonId = String(personId || "");
  const cleanSeasonId = String(seasonId || state.filters.participants.seasonId || "");
  let response = null;

  if (!cleanPersonId || !cleanSeasonId) {
    showToast("Faltan datos", "Define persona y temporada antes de intentar la limpieza scrap.", "warning");
    return;
  }

  await withLoading(async () => {
    response = await apiPost("scrap.deleteSeasonAssignments", {
      seasonId: cleanSeasonId,
      personId: cleanPersonId
    });
    invalidateDashboardSeasonMatrix_();
    invalidateWelcomeCache_();
    const refreshResults = await Promise.allSettled([
      refreshPeopleSources_(),
      loadWelcomePeople_({
        force: true,
        showLoading: false
      }),
      loadParticipantSeasonAssignments_({
        force: true,
        seasonId: cleanSeasonId,
          showLoading: false
        })
    ]);

    refreshResults
      .filter((result) => result.status === "rejected")
      .forEach((result) => {
        console.error("SCRAP season refresh warning", result.reason);
      });

    try {
      await loadParticipantsData({
        force: true,
        showLoading: false
      });
    } catch (error) {
      console.error("SCRAP participants reload warning", error);
    }
  }, "Eliminando scrap de la temporada...");

  showToast(
    "Scrap eliminado de la temporada",
    `${response?.personName || "La persona"} fue retirada de ${response?.deletedParticipants || 0} registro(s) de participantes y ${response?.deletedAttendances || 0} asistencia(s) en ${response?.seasonName || cleanSeasonId}.`,
    "success"
  );
  renderApp();
}

async function loadScrapDeletePreview_(personId, options = {}) {
  const cleanPersonId = String(personId || "").trim();

  if (!cleanPersonId) {
    state.ui.selectedScrapPersonId = "";
    state.ui.scrapPreview = null;
    return null;
  }

  if (
    !options.force &&
    String(state.ui.selectedScrapPersonId || "") === cleanPersonId &&
    String(state.ui.scrapPreview?.personId || "") === cleanPersonId
  ) {
    return state.ui.scrapPreview;
  }

  const task = async () => {
    let preview = null;

    try {
      preview = await apiGet("scrap.previewPerson", {
        personId: cleanPersonId
      });
    } catch (error) {
      if (isUnknownActionError_(error, "scrap.previewPerson")) {
        state.ui.selectedScrapPersonId = cleanPersonId;
        state.ui.scrapPreview = null;
        return null;
      }

      throw error;
    }

    state.ui.selectedScrapPersonId = cleanPersonId;
    state.ui.scrapPreview = preview;
    return preview;
  };

  if (options.showLoading === false) {
    return task();
  }

  return withLoading(task, options.message || "Analizando impacto del borrado...");
}

