function applyScrapDeletePersonLocally_(personId) {
  const cleanPersonId = String(personId || "").trim();

  if (!cleanPersonId) {
    return;
  }

  state.people = (Array.isArray(state.people) ? state.people : []).filter((person) => String(person?.id || "").trim() !== cleanPersonId);
  state.peopleDirectory = (Array.isArray(state.peopleDirectory) ? state.peopleDirectory : []).filter((person) => String(person?.id || "").trim() !== cleanPersonId);
  state.welcomePeople = (Array.isArray(state.welcomePeople) ? state.welcomePeople : []).filter((person) => String(person?.id || "").trim() !== cleanPersonId);
  state.formationCandidates = (Array.isArray(state.formationCandidates) ? state.formationCandidates : []).filter((item) => String(item?.personId || "").trim() !== cleanPersonId);
  state.formationRecords = (Array.isArray(state.formationRecords) ? state.formationRecords : []).filter((item) => String(item?.personId || "").trim() !== cleanPersonId);
  state.formationEnrollments = (Array.isArray(state.formationEnrollments) ? state.formationEnrollments : []).filter((item) => String(item?.personId || "").trim() !== cleanPersonId);
  state.formationProfilesByKey = {};
  state.ui.scrapPreview = String(state.ui.scrapPreview?.personId || "") === cleanPersonId ? null : state.ui.scrapPreview;
  state.ui.selectedScrapPersonId = String(state.ui.selectedScrapPersonId || "") === cleanPersonId ? "" : state.ui.selectedScrapPersonId;

  if (String(state.ui.selectedFormationPersonId || "") === cleanPersonId) {
    state.ui.selectedFormationPersonId = "";
    state.formationProfile = null;
  }

  state.metrics.peopleCount = state.people.length;
  state.metrics.directoryCount = state.peopleDirectory.length;
}

async function executeScrapDeleteSeason_(seasonId) {
  const cleanSeasonId = String(seasonId || "").trim();
  let response = null;

  if (!cleanSeasonId) {
    showToast("Falta temporada", "Selecciona la temporada demo que deseas eliminar.", "warning");
    return;
  }

  try {
    await withLoading(async () => {
      response = await apiPost("scrap.deleteSeason", {
        seasonId: cleanSeasonId
      });

      applyScrapDeleteSeasonLocally_(cleanSeasonId);
      invalidateDashboardSeasonMatrix_();
      invalidateWelcomeCache_();

      await refreshSeasons();
      syncBootstrapFilters_();
      await syncAllFilters();

      const refreshResults = await Promise.allSettled([
        loadWelcomePeople_({
          force: true,
          showLoading: false
        }),
        state.currentView === "dashboard"
          ? ensureDashboardViewData_({
            force: true,
            showLoading: false
          })
          : Promise.resolve(),
        state.currentView === "participants"
          ? loadParticipantsData({
            force: true,
            showLoading: false
          })
          : Promise.resolve(),
        state.currentView === "attendance"
          ? loadAttendanceData({
            force: true,
            showLoading: false
          })
          : Promise.resolve(),
        state.currentView === "qr"
          ? ensureQrViewData_({
            force: true,
            showLoading: false
          })
          : Promise.resolve()
      ]);

      refreshResults
        .filter((result) => result.status === "rejected")
        .forEach((result) => {
          console.error("SCRAP season refresh warning", result.reason);
        });
    }, "Eliminando temporada demo...");
  } catch (error) {
    if (error instanceof ApiError && String(error.code || "").toUpperCase() === "SCRAP_SEASON_BLOCKED_BY_FORMATION") {
      showToast(
        "Temporada bloqueada",
        `Aún hay ${error.details?.linkedFormationRecords || 0} registro(s) y ${error.details?.linkedFormationEnrollments || 0} inscripción(es) de Formación ligadas a esta temporada. Primero limpia a la persona demo con SCRAP total y luego vuelve aquí.`,
        "warning"
      );
      renderApp();
      scrollToSection_("admin-scrap-center");
      return;
    }

    throw error;
  }

  showToast(
    "Temporada demo eliminada",
    `${response?.seasonName || cleanSeasonId} se eliminó con ${response?.deletedSessions || 0} sesión(es), ${response?.deletedSessionGroups || 0} grupo(s) por sesión, ${response?.deletedParticipants || 0} participante(s) y ${response?.deletedAttendances || 0} asistencia(s).`,
    "success"
  );
  renderApp();
  scrollToSection_("admin-scrap-center");
}

